def get_template_content(msg_type, **replace):
    """msg_type에 해당하는 제목/본문 반환. replace로 order_id 등 치환값 전달."""
    t = MessageTemplate.query.filter_by(msg_type=msg_type).first()
    if t and t.title:
        title, body = t.title, (t.body or '')
    else:
        title, body = _DEFAULT_MESSAGES.get(msg_type, ('알림', ''))
    if replace:
        for k, v in (replace or {}).items():
            body = body.replace('{' + k + '}', str(v))
    return title, body


def _point_in_polygon(px, py, polygon):
    """점 (px, py)가 polygon [[x,y],...] 안에 있는지 (ray casting)."""
    if not polygon or len(polygon) < 3:
        return False
    n = len(polygon)
    inside = False
    j = n - 1
    for i in range(n):
        xi, yi = polygon[i][0], polygon[i][1]
        xj, yj = polygon[j][0], polygon[j][1]
        if yi == yj:
            j = i
            continue
        if ((yi > py) != (yj > py)) and (px < (xj - xi) * (py - yi) / (yj - yi) + xi):
            inside = not inside
        j = i
    return inside


def _polygon_point_as_xy(polygon, point_lat, point_lng):
    """폴리곤이 [lat,lng] vs [lng,lat] 중 어떤 형식인지 추정해, 점을 (x,y)로 반환. 한국 위도 33~43, 경도 124~132."""
    if not polygon or len(polygon) < 1:
        return (point_lat, point_lng)
    a0, a1 = polygon[0][0], polygon[0][1]
    if 124 <= a0 <= 132 and 33 <= a1 <= 43:
        return (point_lng, point_lat)
    if 124 <= a1 <= 132 and 33 <= a0 <= 43:
        return (point_lat, point_lng)
    return (point_lat, point_lng)


def _geocode_address(address_str):
    """주소 문자열을 (lat, lng)로 변환. Nominatim 시도 후 실패 시 Photon(무료) 폴백. 결과는 주소별 캐시."""
    if not address_str or not address_str.strip():
        return None
    addr = address_str.strip()
    # 간단 인메모리 캐시 (최대 500개, 동일 주소 재요청 시 즉시 반환)
    if not hasattr(_geocode_address, '_cache'):
        _geocode_address._cache = {}
        _geocode_address._cache_keys = []
    _cache, _keys = _geocode_address._cache, _geocode_address._cache_keys
    if addr in _cache:
        return _cache[addr]
    _max = 500
    if len(_keys) >= _max:
        for k in _keys[:_max // 4]:
            _cache.pop(k, None)
        _geocode_address._cache_keys = _keys[_max // 4:]
        _keys = _geocode_address._cache_keys

    # 한국 주소는 국가명 포함 시 성공률 상승
    q_nominatim = addr if ("대한민국" in addr or "한국" in addr or "South Korea" in addr) else (addr + " 대한민국")

    # 1) Nominatim (OpenStreetMap)
    try:
        r = requests.get(
            "https://nominatim.openstreetmap.org/search",
            params={"q": q_nominatim, "format": "json", "limit": 1},
            headers={"User-Agent": "BasketUncle/1.0 (https://github.com/basket-uncle; address-check)"},
            timeout=10,
        )
        if r.status_code == 200:
            data = r.json()
            if data and len(data) > 0 and data[0].get("lat") and data[0].get("lon"):
                result = (float(data[0]["lat"]), float(data[0]["lon"]))
                _cache[addr] = result
                _geocode_address._cache_keys.append(addr)
                return result
    except Exception:
        pass

    # 2) Photon (Komoot, 무료·API키 불필요, OSM 기반)
    try:
        r = requests.get(
            "https://photon.komoot.io/api/",
            params={"q": addr, "limit": 1, "lang": "ko"},
            headers={"User-Agent": "BasketUncle/1.0"},
            timeout=8,
        )
        if r.status_code == 200:
            data = r.json()
            features = data.get("features") or []
            if features:
                coords = features[0].get("geometry", {}).get("coordinates")
                if coords and len(coords) >= 2:
                    result = (float(coords[1]), float(coords[0]))
                    _cache[addr] = result
                    _geocode_address._cache_keys.append(addr)
                    return result
    except Exception:
        pass
    _cache[addr] = None
    _geocode_address._cache_keys.append(addr)
    return None


def _reverse_geocode_to_zip(lat, lng):
    """위경도 역지오코딩으로 우편번호 조회. 캐시 사용(최대 500개). KAKAO_REST_API_KEY 있으면 카카오 로컬 API(한국 5자리 정확), 없으면 Nominatim 폴백."""
    if lat is None or lng is None:
        return ''
    try:
        key = (round(float(lat), 4), round(float(lng), 4))
    except (TypeError, ValueError):
        return ''
    if not hasattr(_reverse_geocode_to_zip, '_cache'):
        _reverse_geocode_to_zip._cache = {}
        _reverse_geocode_to_zip._keys = []
    _cache, _keys = _reverse_geocode_to_zip._cache, _reverse_geocode_to_zip._keys
    if key in _cache:
        return _cache[key]
    _max = 500
    if len(_keys) >= _max:
        for k in _keys[:_max // 4]:
            _cache.pop(k, None)
        _reverse_geocode_to_zip._keys = _keys[_max // 4:]
        _keys = _reverse_geocode_to_zip._keys
    postcode = ''

    # 1) 카카오 로컬 API (한국 5자리 우편번호 정확)
    try:
        kakao_key = KAKAO_REST_API_KEY
        if kakao_key:
            r = requests.get(
                "https://dapi.kakao.com/v2/local/geo/coord2address.json",
                params={"x": lng, "y": lat, "input_coord": "WGS84"},
                headers={"Authorization": f"KakaoAK {kakao_key}"},
                timeout=8,
            )
            if r.status_code == 200:
                data = r.json()
                docs = (data or {}).get("documents") or []
                if docs:
                    doc = docs[0]
                    ra = doc.get("road_address") or {}
                    postcode = (ra.get("zone_no") or "").strip()
                    if not postcode and doc.get("address"):
                        postcode = (doc["address"].get("zip_code") or "").strip()
    except Exception:
        pass

    # 2) Nominatim 폴백 (한국은 postcode 누락 많음)
    if not postcode:
        try:
            r = requests.get(
                "https://nominatim.openstreetmap.org/reverse",
                params={"lat": lat, "lon": lng, "format": "json", "addressdetails": 1},
                headers={"User-Agent": "BasketUncle/1.0 (https://github.com/basket-uncle; delivery-export)"},
                timeout=8,
            )
            if r.status_code == 200:
                data = r.json()
                addr = (data or {}).get("address") or {}
                postcode = (addr.get("postcode") or addr.get("postal_code") or "").strip()
        except Exception:
            pass

    _cache[key] = postcode
    _reverse_geocode_to_zip._keys.append(key)
    return postcode


def _address_to_zip_kakao(address_str):
    """주소 문자열로 카카오 주소 검색 API 호출 → 5자리 우편번호(zone_no) 반환. 캐시(최대 300개)."""
    if not address_str or not address_str.strip():
        return ''
    addr = address_str.strip()
    m = re.match(r'\(([^)]+)\)', addr)
    if m:
        addr = m.group(1).strip()
    if not addr:
        return ''
    if not hasattr(_address_to_zip_kakao, '_cache'):
        _address_to_zip_kakao._cache = {}
        _address_to_zip_kakao._keys = []
    _cache, _keys = _address_to_zip_kakao._cache, _address_to_zip_kakao._keys
    if addr in _cache:
        return _cache[addr]
    _max = 300
    if len(_keys) >= _max:
        for k in _keys[:_max // 3]:
            _cache.pop(k, None)
        _address_to_zip_kakao._keys = _keys[_max // 3:]
        _keys = _address_to_zip_kakao._keys
    postcode = ''
    try:
        kakao_key = KAKAO_REST_API_KEY
        if kakao_key:
            r = requests.get(
                "https://dapi.kakao.com/v2/local/search/address.json",
                params={"query": addr},
                headers={"Authorization": f"KakaoAK {kakao_key}"},
                timeout=8,
            )
            if r.status_code == 200:
                data = r.json()
                docs = (data or {}).get("documents") or []
                if docs:
                    doc = docs[0]
                    ra = doc.get("road_address") or {}
                    postcode = (ra.get("zone_no") or "").strip()
                    if not postcode and doc.get("address"):
                        postcode = (doc["address"].get("zip_code") or "").strip()
    except Exception:
        pass
    _cache[addr] = postcode
    _address_to_zip_kakao._keys.append(addr)
    return postcode


def _order_delivery_zip(order):
    """주문의 배송지 주소를 우편번호로 변환. KAKAO_REST_API_KEY 있으면 카카오 API 우선(한국 5자리 정확), 없으면 좌표 역지오코딩 또는 주소 지오코딩 후 역지오코딩."""
    if not order:
        return ''
    lat, lng = getattr(order, 'delivery_lat', None), getattr(order, 'delivery_lng', None)
    if lat is not None and lng is not None:
        return _reverse_geocode_to_zip(lat, lng)
    addr = (order.delivery_address or '').strip()
    if not addr:
        return ''
    # 주소만 있을 때: 카카오 주소 검색으로 우편번호 직접 조회(정확) → 실패 시 기존 지오코딩+역지오코딩
    if KAKAO_REST_API_KEY:
        z = _address_to_zip_kakao(addr)
        if z:
            return z
    coords = _geocode_address(addr)
    if coords:
        return _reverse_geocode_to_zip(coords[0], coords[1])
    return ''


def _bunji_code_from_address(address_str):
    """주소에서 번지(예: 1-1, 123-45) 추출 후 표기. 1-1 → 00001_1, 123-45 → 123_45 (한 자리 수는 5자리 패딩, 그 외는 그대로)."""
    if not address_str or not address_str.strip():
        return None
    s = address_str.strip()
    m = re.search(r'(\d+)\s*-\s*(\d+)', s)
    if not m:
        return None
    try:
        first, second = int(m.group(1)), int(m.group(2))
        first_str = f"{first:05d}" if first < 10 else str(first)
        return f"{first_str}_{second}"
    except (ValueError, TypeError):
        return None


def _make_order_virt_id(delivery_address):
    """오더넘버: order + 번지수(5자리) + 주문날짜2자리(MM) + 숫자증가(001~). 유일 보장."""
    prefix = "order"
    mm = now_kst().strftime("%m")  # 01~12 (KST)
    # 기존 order_id 중 prefix 다음 5자리가 숫자인 것의 최대값+1 (번지수)
    candidates = db.session.query(Order.order_id).filter(Order.order_id.like(prefix + "%")).all()
    next_idx = 1
    for (oid,) in candidates:
        if oid and len(oid) >= len(prefix) + 5 and oid[len(prefix):len(prefix) + 5].isdigit():
            next_idx = max(next_idx, int(oid[len(prefix):len(prefix) + 5]) + 1)
            
    # 동일 번지수+MM 기준 마지막 3자리(숫자증가) 최대값+1
    pattern = f"{prefix}{next_idx:05d}{mm}"
    seq_candidates = db.session.query(Order.order_id).filter(Order.order_id.like(pattern + "%")).all()
    next_seq = 1
    for (oid,) in seq_candidates:
        if not oid: continue
        # ★ 핵심 수정: 언더바(_) 뒤의 타임스탬프를 떼어내고 순서(001, 002)만 정확히 계산하도록 변경
        clean_oid = oid.split('_')[0] 
        if len(clean_oid) == len(pattern) + 3 and clean_oid[len(pattern):].isdigit():
            next_seq = max(next_seq, int(clean_oid[len(pattern):]) + 1)
            
    for _ in range(100):
        candidate = f"{prefix}{next_idx:05d}{mm}{next_seq:03d}"
        # 언더바(_)가 포함된 기존 주문번호와도 겹치지 않게 like 검색으로 확실히 확인
        if not db.session.query(Order.order_id).filter(Order.order_id.like(candidate + "%")).first():
            return candidate
        next_seq += 1
        
    return f"{prefix}{next_idx:05d}{mm}{next_seq:03d}"


def _get_quick_region_list(zone):
    """DeliveryZone.quick_region_names JSON 파싱. 빈값이면 빈 리스트."""
    if not zone or not getattr(zone, 'quick_region_names', None):
        return []
    try:
        names = json.loads(zone.quick_region_names)
        return [str(n).strip() for n in names if n and str(n).strip()]
    except Exception:
        return []


def _get_zone():
    """최신 배송권역 1건."""
    return DeliveryZone.query.order_by(DeliveryZone.updated_at.desc()).first()


def get_main_display_config():
    """메인 화면 노출 설정. (메인 카테고리 개수, 카테고리당 상품 개수, 최신상품 개수, 마감임박 개수). 없으면 기본값 반환. 60초 캐시로 DB/메타데이터 부하 감소."""
    import time
    cache = getattr(get_main_display_config, '_cache', None)
    if cache is not None and (time.time() - cache[1]) < 60:
        return cache[0]
    _ensure_main_display_config_columns()
    row = MainDisplayConfig.query.get(1)
    if row:
        result = (
            max(1, min(50, getattr(row, 'main_category_count', 8) or 8)),
            max(1, min(100, getattr(row, 'main_products_per_category', 20) or 20)),
            max(1, min(100, getattr(row, 'main_latest_count', 30) or 30)),
            max(1, min(100, getattr(row, 'main_closing_count', 50) or 50)),
        )
    else:
        result = (8, 20, 30, 50)
    get_main_display_config._cache = (result, time.time())
    return result


def _normalize_address_for_zone(address_str):
    """배송권역 검사용 주소 정규화 (마이페이지·결제 동일 적용). strip + 연속 공백 1칸."""
    if not address_str:
        return ""
    s = (address_str or "").strip()
    return re.sub(r"\s+", " ", s)


def is_address_in_main_polygon(address_str):
    """주소가 기본 권역안에 있으면 True (배송권역 기본 추가요금 없음). 폴리곤 [lat,lng]/[lng,lat] 자동 보정."""
    zone = _get_zone()
    addr = (address_str or "").strip()
    if not addr or not zone or not zone.polygon_json:
        return False
    try:
        polygon = json.loads(zone.polygon_json)
        if not polygon or len(polygon) < 3:
            return False
        coords = _geocode_address(addr)
        if not coords:
            return False
        lat, lng = coords[0], coords[1]
        px, py = _polygon_point_as_xy(polygon, lat, lng)
        if _point_in_polygon(px, py, polygon):
            return True
        if _point_in_polygon(py, px, polygon):
            return True
        return False
    except Exception:
        return False


def is_address_in_quick_polygon(address_str):
    """주소가 퀵 권역안에 있으면 True (추가요금 있는 퀵 배송). 폴리곤 좌표 순서 자동 보정."""
    zone = _get_zone()
    addr = (address_str or "").strip()
    if not addr or not zone or not getattr(zone, 'quick_region_polygon_json', None):
        return False
    try:
        quick_poly = json.loads(zone.quick_region_polygon_json)
        if not quick_poly or len(quick_poly) < 3:
            return False
        coords = _geocode_address(addr)
        if not coords:
            return False
        lat, lng = coords[0], coords[1]
        px, py = _polygon_point_as_xy(quick_poly, lat, lng)
        if _point_in_polygon(px, py, quick_poly):
            return True
        if _point_in_polygon(py, px, quick_poly):
            return True
        return False
    except Exception:
        return False


def get_delivery_zone_type(address_str):
    """주소 기준 권역 판별. is_address_in_delivery_zone과 동일한 기준(권역 이름·폴리곤·퀵 이름) 적용 후 normal/quick/unavailable 구분."""
    addr = _normalize_address_for_zone(address_str)
    if not addr:
        return 'unavailable'
    # 마이페이지·결제와 동기화: 배송가능 여부는 is_address_in_delivery_zone 단일 기준
    if not is_address_in_delivery_zone(addr):
        return 'unavailable'
    zone = _get_zone()
    use_quick_only = bool(getattr(zone, 'use_quick_region_only', False)) if zone else False
    if use_quick_only:
        return 'quick'
    if is_address_in_main_polygon(addr):
        return 'normal'
    if is_address_in_quick_polygon(addr):
        return 'quick'
    quick = _get_quick_region_list(zone) if zone else []
    if quick and any(name in addr for name in quick):
        return 'normal'
    # 권역 이름만 맞는 경우(폴리곤/지오코딩 오차 보정) → 기본권역으로 처리
    if zone and getattr(zone, 'name', None) and (zone.name or '').strip() and (zone.name or '').strip() in addr:
        return 'normal'
    # is_address_in_delivery_zone True인데 위에서 안 걸린 경우(폴리곤 swap 등) → 기본권역
    return 'normal'


def get_quick_extra_config():
    """퀵권역 추가요금 정보 반환. (fee, message)."""
    zone = _get_zone()
    fee = 10000
    msg = "해당 주소는 배송권역이 아니거나, 배송권 추가 요금으로 배송합니다. 추가요금과 주문방법 안내드립니다."
    if zone:
        fee = int(getattr(zone, 'quick_extra_fee', None) or 10000)
        if getattr(zone, 'quick_extra_message', None):
            msg = (zone.quick_extra_message or "").strip() or msg
    return fee, msg


def _get_category_delivery_settings(cat_name):
    """카테고리별 배송료 설정 반환. (base_fee, free_over, extra_threshold, extra_fee, fee_per_item)."""
    cat = Category.query.filter_by(name=cat_name).first()
    if not cat:
        return 1900, None, 50000, 1900, 0
    base = int(getattr(cat, 'delivery_base_fee', None) or 1900)
    free_over = getattr(cat, 'delivery_free_over', None)
    if free_over is not None:
        free_over = int(free_over)
    extra_threshold = getattr(cat, 'delivery_extra_threshold', None)
    if extra_threshold is None:
        extra_threshold = 50000
    else:
        extra_threshold = int(extra_threshold)
    extra_fee = int(getattr(cat, 'delivery_extra_fee', None) or 1900)
    per_item = int(getattr(cat, 'delivery_fee_per_item', None) or 0)
    return base, free_over, extra_threshold, extra_fee, per_item


def calc_delivery_fee_for_categories(cat_price_sums, cat_item_counts=None):
    """카테고리별 금액/건별 배송료 계산. Returns (total_fee, breakdown_dict)."""
    if not cat_price_sums:
        return 0, {}
    cat_item_counts = cat_item_counts or {}
    total = 0
    breakdown = {}
    for cat_name, amt in cat_price_sums.items():
        base, free_over, extra_threshold, extra_fee, per_item = _get_category_delivery_settings(cat_name)
        cnt = cat_item_counts.get(cat_name, 0)
        if free_over is not None and amt >= free_over:
            cat_fee = 0 + per_item * cnt
        else:
            add_extra = (extra_fee if (extra_threshold and amt >= extra_threshold) else 0)
            cat_fee = base + add_extra + per_item * cnt
        total += cat_fee
        breakdown[cat_name] = cat_fee
    return total, breakdown


def get_category_delivery_description(cat_name):
    """한 카테고리의 배송료 안내 문구 (상품상세·카테고리 페이지용)."""
    base, free_over, extra_threshold, extra_fee, per_item = _get_category_delivery_settings(cat_name)
    parts = []
    if free_over is not None:
        parts.append(f"{free_over:,}원 이상 구매 시 무료")
    if base and (free_over is None or free_over > 0):
        parts.append(f"기본 {base:,}원")
    if extra_threshold and extra_fee:
        parts.append(f"{extra_threshold:,}원 이상 시 +{extra_fee:,}원")
    if per_item:
        parts.append(f"건당 +{per_item:,}원")
    if not parts:
        return "배송료 문의"
    return " · ".join(parts)


def is_address_in_delivery_zone(address_str):
    """주소가 배송 가능한지 (기본 권역이든 퀵 권역이든 포함). use_quick_region_only 시 퀵권역만 배송가능. 마이페이지·결제 동일 정규화 적용."""
    zone = _get_zone()
    addr = _normalize_address_for_zone(address_str)
    if not addr:
        return False
    use_quick_only = bool(getattr(zone, 'use_quick_region_only', False)) if zone else False
    if use_quick_only:
        if is_address_in_quick_polygon(addr):
            return True
        quick = _get_quick_region_list(zone)
        return bool(quick and any(name in addr for name in quick))
    if is_address_in_main_polygon(addr):
        return True
    if is_address_in_quick_polygon(addr):
        return True
    quick = _get_quick_region_list(zone) if zone else []
    if quick:
        return any(name in addr for name in quick)
    # 배송권역 이름(예: 연수구)이 주소에 있으면 배송가능으로 처리 (지오코딩/폴리곤 오차 보정)
    if zone and getattr(zone, 'name', None) and (zone.name or '').strip():
        if (zone.name or '').strip() in addr:
            return True
    if zone and zone.polygon_json:
        try:
            polygon = json.loads(zone.polygon_json)
            if polygon and len(polygon) >= 3:
                coords = _geocode_address(addr)
                if coords:
                    lat, lng = coords[0], coords[1]
                    px, py = _polygon_point_as_xy(polygon, lat, lng)
                    if _point_in_polygon(px, py, polygon):
                        return True
                    # 폴리곤이 [lng,lat]인데 [lat,lng]로 추정된 경우 등 좌표 순서 반대 시 한 번 더 시도
                    if _point_in_polygon(py, px, polygon):
                        return True
        except Exception:
            pass
    return False


def _get_user_total_paid(user_id):
    """회원 누적 결제 기준 실제 결제금액: 배송완료된 품목 금액만 집계 (취소·환불 주문 제외)."""
    total = db.session.query(
        func.coalesce(func.sum(OrderItem.price * OrderItem.quantity), 0)
    ).join(Order, OrderItem.order_id == Order.id).filter(
        Order.user_id == user_id,
        Order.status.notin_(['취소', '환불']),
        OrderItem.cancelled == False,
        OrderItem.item_status == '배송완료'
    ).scalar()
    return int(total) if total is not None else 0


def _get_member_grade_config():
    """회원 등급 기준 금액 반환. (min_grade2, min_grade3, min_grade4, min_grade5) 순서."""
    def get_val(k, default=0):
        row = MemberGradeConfig.query.filter_by(key=k).first()
        if not row or not row.value:
            return default
        try:
            return int(row.value)
        except (ValueError, TypeError):
            return default
    return (
        get_val('min_amount_grade2', 100000),
        get_val('min_amount_grade3', 500000),
        get_val('min_amount_grade4', 1000000),
        get_val('min_amount_grade5', 2000000),
    )


def recompute_member_grade_for_user(user):
    """결제 누적 금액 기준으로 등급 재계산. member_grade_overridden 이면 변경하지 않음. 반환: 변경 여부."""
    if getattr(user, 'member_grade_overridden', False):
        return False
    total = _get_user_total_paid(user.id)
    min2, min3, min4, min5 = _get_member_grade_config()
    new_grade = 1
    if total >= min5:
        new_grade = 5
    elif total >= min4:
        new_grade = 4
    elif total >= min3:
        new_grade = 3
    elif total >= min2:
        new_grade = 2
    if user.member_grade != new_grade:
        user.member_grade = new_grade
        return True
    return False


def categories_for_member_grade(member_grade):
    """해당 등급 회원이 이용 가능한 카테고리 목록. member_grade는 1~5, 널이면 1로 간주."""
    grade = 1 if member_grade is None else max(1, min(5, member_grade))
    return Category.query.filter(
        or_(Category.min_member_grade.is_(None), Category.min_member_grade <= grade)
    ).order_by(Category.order.asc(), Category.id.asc())


def _get_point_config():
    """포인트 정책 반환. accumulation_rate: 1=0.1%, min_order_to_use(원), max_points_per_order(원)"""
    def get_val(k, default=0):
        row = PointConfig.query.filter_by(key=k).first()
        if not row or not row.value:
            return default
        try:
            return int(row.value)
        except (ValueError, TypeError):
            return default
    return (
        get_val('accumulation_rate', 1),
        get_val('min_order_to_use', 30000),
        get_val('max_points_per_order', 3000),
    )


def _get_point_config_val(key, default=0):
    """단일 포인트 설정값 정수 반환."""
    row = PointConfig.query.filter_by(key=key).first()
    if not row or row.value is None or row.value == '':
        return default
    try:
        return int(row.value)
    except (ValueError, TypeError):
        return default


def _get_point_policy(ptype, grade):
    """유형·등급별 포인트 사용 정책. ptype: accumulated/event/cash, grade: 1~5.
    먼저 {ptype}_grade_{grade}_* 조회, 0이면 유형 기본값·전역값 사용."""
    rate, global_min_order, global_max_order = _get_point_config()
    g = max(1, min(5, int(grade) if grade is not None else 1))
    min_order = _get_point_config_val(f'{ptype}_grade_{g}_min_order', 0)
    valid_days = _get_point_config_val(f'{ptype}_grade_{g}_valid_days', 0)
    max_count = _get_point_config_val(f'{ptype}_grade_{g}_max_use_count', 0)
    max_per_order = _get_point_config_val(f'{ptype}_grade_{g}_max_use_per_order', 0)
    if min_order <= 0:
        min_order = _get_point_config_val(f'{ptype}_min_order_amount', 0)
    if min_order <= 0:
        min_order = global_min_order
    if max_per_order <= 0:
        max_per_order = _get_point_config_val(f'{ptype}_max_use_per_order', 0)
    if max_per_order <= 0:
        max_per_order = global_max_order
    if valid_days <= 0:
        valid_days = _get_point_config_val(f'{ptype}_valid_days', 0)
    if max_count <= 0:
        max_count = _get_point_config_val(f'{ptype}_max_use_count', 0)
    return {
        'min_order_amount': min_order,
        'valid_days': valid_days,
        'max_use_count': max_count,
        'max_use_per_order': max_per_order,
    }


def _point_use_count_in_days(user_id, ptype, days):
    """해당 유형 포인트를 최근 days일 내 사용한 횟수(주문 기준)."""
    if not user_id or days <= 0:
        return 0
    since = now_kst() - timedelta(days=days)
    return PointLog.query.filter(
        PointLog.user_id == user_id,
        PointLog.point_type == ptype,
        PointLog.amount < 0,
        PointLog.created_at >= since,
    ).count()


def _effective_max_point_use(user, order_total):
    """회원이 이 주문에서 사용 가능한 최대 포인트(원). 레벨별·유형별 정책 적용."""
    if not user or order_total is None:
        return 0
    grade = max(1, min(5, getattr(user, 'member_grade', 1) or 1))
    available = 0
    for ptype, col in [
        (POINT_TYPE_ACCUMULATED, 'points_accumulated'),
        (POINT_TYPE_EVENT, 'points_event'),
        (POINT_TYPE_CASH, 'points_cash'),
    ]:
        balance = getattr(user, col, 0) or 0
        if balance <= 0:
            continue
        policy = _get_point_policy(ptype, grade)
        if order_total < policy['min_order_amount']:
            continue
        if policy['valid_days'] > 0 and policy['max_use_count'] > 0:
            used_count = _point_use_count_in_days(user.id, ptype, policy['valid_days'])
            if used_count >= policy['max_use_count']:
                continue
        cap = min(balance, policy['max_use_per_order'])
        available += cap
    return available


def _sync_user_points(user_obj):
    """User의 points_accumulated, points_event, points_cash 합을 user.points에 반영."""
    if not user_obj:
        return
    total = (getattr(user_obj, 'points_accumulated', 0) or 0) + (getattr(user_obj, 'points_event', 0) or 0) + (getattr(user_obj, 'points_cash', 0) or 0)
    user_obj.points = total


def apply_welcome_event_points(user_obj):
    """첫 가입 시 이벤트 포인트 자동 지급. SignupWelcomeConfig.points_amount(원) 또는 PointConfig welcome_event_points 사용. 0이면 미지급."""
    if not user_obj:
        return
    amount = 0
    row = SignupWelcomeConfig.query.get(1)
    if row is not None and getattr(row, 'points_amount', None) is not None:
        amount = max(0, int(row.points_amount))
    if amount <= 0:
        amount = _get_point_config_val('welcome_event_points', 0)
    if amount <= 0:
        return
    _ensure_user_point_columns(user_obj)
    cur = getattr(user_obj, 'points_event', 0) or 0
    setattr(user_obj, 'points_event', cur + amount)
    db.session.add(PointLog(user_id=user_obj.id, amount=amount, point_type=POINT_TYPE_EVENT, memo='가입 축하 이벤트'))
    _sync_user_points(user_obj)


def _ensure_user_point_columns(user_obj):
    """기존에 points만 있고 3종 컬럼이 0인 경우, points를 적립포인트로 간주해 동기화."""
    if not user_obj:
        return
    pa = getattr(user_obj, 'points_accumulated', 0) or 0
    pe = getattr(user_obj, 'points_event', 0) or 0
    pc = getattr(user_obj, 'points_cash', 0) or 0
    if (pa + pe + pc) == 0 and (getattr(user_obj, 'points', 0) or 0) > 0:
        user_obj.points_accumulated = user_obj.points
    _sync_user_points(user_obj)


def apply_order_points(user, order_total, points_used, order_id=None):
    """결제 완료 시 포인트 사용분 차감. 사용 우선순위: 이벤트 → 캐시충전 → 적립.
    포인트 사용분은 당일 주문/차감에서 차감한 뒤 별도 정산에서 처리하며, MarketingCost에 기록."""
    user_obj = user if hasattr(user, 'points') else User.query.get(user)
    if not user_obj or points_used <= 0:
        return
    _ensure_user_point_columns(user_obj)
    remaining = points_used
    # 이벤트 → 캐시충전 → 적립 순으로 차감
    for col, ptype in [
        ('points_event', POINT_TYPE_EVENT),
        ('points_cash', POINT_TYPE_CASH),
        ('points_accumulated', POINT_TYPE_ACCUMULATED),
    ]:
        if remaining <= 0:
            break
        cur = getattr(user_obj, col, 0) or 0
        deduct = min(cur, remaining)
        if deduct > 0:
            setattr(user_obj, col, cur - deduct)
            db.session.add(PointLog(user_id=user_obj.id, amount=-deduct, point_type=ptype, order_id=order_id, memo='주문 사용'))
            remaining -= deduct
    _sync_user_points(user_obj)
    db.session.add(MarketingCost(order_id=order_id, user_id=user_obj.id, amount=points_used, memo='고객 포인트 사용 (별도 정산)'))


def apply_points_on_delivery_complete(order_item):
    """품목 배송완료 시 적립. 해당 품목의 정산번호(sales_amount) 기준으로 적립포인트만 적립. 1회만 적립."""
    if not order_item or getattr(order_item, 'cancelled', False):
        return
    order = Order.query.get(order_item.order_id) if order_item.order_id else None
    if not order or not order.user_id:
        return
    if PointLog.query.filter_by(order_item_id=order_item.id).filter(PointLog.amount > 0).first():
        return
    st = Settlement.query.filter_by(order_item_id=order_item.id).first()
    if not st or not getattr(st, 'sales_amount', 0):
        return
    rate, _, _ = _get_point_config()
    earned = int(st.sales_amount * rate / 1000) if rate else 0
    if earned <= 0:
        return
    u = User.query.get(order.user_id)
    if not u:
        return
    u.points_accumulated = (getattr(u, 'points_accumulated', 0) or 0) + earned
    _sync_user_points(u)
    db.session.add(PointLog(user_id=u.id, amount=earned, point_type=POINT_TYPE_ACCUMULATED, order_id=order.id, order_item_id=order_item.id, memo='배송완료 적립'))


@login_manager.user_loader
def load_user(user_id):
    if not user_id:
        return None
    try:
        return User.query.get(int(user_id))
    except (TypeError, ValueError):
        return None

