from PIL import Image, ImageOps

ALLOWED_IMAGE_EXTENSIONS = (".jpg", ".jpeg", ".png", ".gif", ".webp")

def _is_allowed_image_filename(filename):
    """업로드 파일이 허용 이미지 확장자인지 검사 (보안: 실행 파일 등 차단)"""
    if not filename:
        return False
    ext = os.path.splitext(secure_filename(filename))[1].lower()
    return ext in ALLOWED_IMAGE_EXTENSIONS

def save_uploaded_file(file):
    """핸드폰 사진 비율 정리(중앙 크롭)·압축(WebP). Cloudinary가 설정되어 있으면 Cloudinary로 업로드."""
    if not file or not getattr(file, 'filename', None):
        return None
    if getattr(file, 'stream', None) and hasattr(file.stream, 'seek'):
        try: file.stream.seek(0)
        except Exception: pass
    fn = (file.filename or '').strip()
    if not fn:
        fn = 'upload.jpg'
    if not _is_allowed_image_filename(fn):
        return None
    try:
        if getattr(file, 'stream', None) and hasattr(file.stream, 'seek'):
            try: file.stream.seek(0)
            except Exception: pass
        file_bytes = file.read()
        if not file_bytes:
            print("[save_uploaded_file] file.read() returned empty bytes")
            return None
        # 1) Cloudinary 업로드 시도 (실패하면 로컬 저장으로 자동 폴백)
        if cloudinary_url:
            try:
                upload_res = cloudinary.uploader.upload(
                    file_bytes,
                    folder="basket-uncle/main",
                )
                url = upload_res.get("secure_url") or upload_res.get("url")
                if not url:
                    print(f"[save_uploaded_file] Cloudinary returned no URL: {upload_res}")
                else:
                    if "/upload/" in url:
                        url = url.replace("/upload/", "/upload/w_800,h_800,c_fill/")
                    return url
            except Exception as ce:
                print(f"[save_uploaded_file] Cloudinary upload failed, fallback to local: {ce}")
                import traceback; traceback.print_exc()

        # 2) 로컬 저장 (Cloudinary 미설정이거나 실패 시)
        img = Image.open(BytesIO(file_bytes))
        img = ImageOps.exif_transpose(img)
        size = (800, 800)
        img = ImageOps.fit(img, size, Image.Resampling.LANCZOS)
        new_filename = f"uncle_{now_kst().strftime('%Y%m%d_%H%M%S_%f')}.webp"
        save_path = os.path.join(app.config['UPLOAD_FOLDER'], new_filename)
        img.save(save_path, "WEBP", quality=85)
        return f"/static/uploads/{new_filename}"
    except Exception as e:
        print(f"[save_uploaded_file] ERROR: {e}")
        import traceback; traceback.print_exc()
        return None


def save_detail_image(file):
    """상세이미지 업로드. Cloudinary 시 원본 업로드 후 URL에 w_1200,c_limit 변환 적용. 로컬 시 가로 1200px 리사이즈."""
    if not file or not getattr(file, 'filename', None):
        return None
    if getattr(file, 'stream', None) and hasattr(file.stream, 'seek'):
        try: file.stream.seek(0)
        except Exception: pass
    fn = (file.filename or '').strip()
    if not fn:
        fn = 'upload.jpg'
    if not _is_allowed_image_filename(fn):
        return None
    try:
        if getattr(file, 'stream', None) and hasattr(file.stream, 'seek'):
            try: file.stream.seek(0)
            except Exception: pass
        file_bytes = file.read()
        if not file_bytes:
            return None
        if cloudinary_url:
            upload_res = cloudinary.uploader.upload(
                file_bytes,
                folder="basket-uncle/detail",
            )
            url = upload_res.get("secure_url") or upload_res.get("url")
            if url and "/upload/" in url:
                url = url.replace("/upload/", "/upload/w_1200,c_limit/")
            return url
        img = Image.open(BytesIO(file_bytes))
        img = ImageOps.exif_transpose(img)
        w, h = img.size
        if w > 1200:
            ratio = 1200 / w
            img = img.resize((1200, int(h * ratio)), Image.Resampling.LANCZOS)
        new_filename = f"detail_{now_kst().strftime('%Y%m%d_%H%M%S_%f')}.webp"
        save_path = os.path.join(app.config['UPLOAD_FOLDER'], new_filename)
        img.save(save_path, "WEBP", quality=88)
        return f"/static/uploads/{new_filename}"
    except Exception as e:
        print(f"[save_detail_image] ERROR: {e}")
        return None


def save_review_image(file):
    """리뷰용 이미지 최적화 후 저장 (최대 640px). Cloudinary 설정 시 Cloudinary 사용."""
    if not file or file.filename == '' or not _is_allowed_image_filename(file.filename):
        return None
    try:
        if getattr(file, 'stream', None) and hasattr(file.stream, 'seek'):
            try: file.stream.seek(0)
            except Exception: pass
        file_bytes = file.read()
        if not file_bytes:
            return None
        if cloudinary_url:
            upload_res = cloudinary.uploader.upload(
                file_bytes,
                folder="basket-uncle/reviews",
            )
            url = upload_res.get("secure_url") or upload_res.get("url")
            if url and "/upload/" in url:
                url = url.replace("/upload/", "/upload/w_640,h_640,c_fill/")
            return url
        review_folder = os.path.join(app.config['UPLOAD_FOLDER'], 'reviews')
        os.makedirs(review_folder, exist_ok=True)
        new_filename = f"review_{now_kst().strftime('%Y%m%d_%H%M%S_%f')}.webp"
        save_path = os.path.join(review_folder, new_filename)
        img = Image.open(BytesIO(file_bytes))
        img = ImageOps.exif_transpose(img)
        size = (640, 640)
        img = ImageOps.fit(img, size, Image.Resampling.LANCZOS)
        img.save(save_path, "WEBP", quality=82)
        return f"/static/uploads/reviews/{new_filename}"
    except Exception as e:
        print(f"[save_review_image] ERROR: {e}")
        return None

def save_board_image(file):
    """게시판(전국맛집요청 등) 이미지 최적화 저장. Cloudinary 설정 시 Cloudinary 사용."""
