# ✅ 개별 정산 승인을 위한 라우트 신설
@login_required
def admin_settle_order(order_id):
    """주문별 정산 확정 처리 및 DB 저장"""
    if not current_user.is_admin:
        flash("관리자 권한이 필요합니다.")
        return redirect('/')
    
    order = Order.query.get_or_404(order_id)
    
    if not order.is_settled:
        order.is_settled = True
        order.settled_at = now_kst() # 정산 시점 기록
        
        try:
            db.session.commit() # ✅ 실제 DB에 강제 기록
            flash(f"주문 {order.order_id[-8:]} 입금 승인 완료!")
        except Exception as e:
            db.session.rollback()
            flash(f"저장 오류: {str(e)}")
    else:
        flash("이미 처리된 주문입니다.")
        
    # ✅ 사용자가 보던 날짜 필터가 유지되도록 이전 페이지(referrer)로 리다이렉트
    return redirect(request.referrer or url_for('admin.admin_dashboard', tab='orders'))
# admin() 함수 내 주문 조회 부분은 기존과 동일하게 유지하되 UI에서 필드를 사용함
@login_required
def admin_bulk_request_delivery():
    """여러 주문을 한꺼번에 배송 요청 상태로 변경 (새로고침 없음)"""
    if not (current_user.is_admin or Category.query.filter_by(manager_email=current_user.email).first()):
        return jsonify({"success": False, "message": "권한이 없습니다."}), 403
    
    data = request.get_json()
    order_ids = data.get('order_ids', [])
    
    if not order_ids:
        return jsonify({"success": False, "message": "선택된 주문이 없습니다."})

    # '결제완료' 상태인 주문들만 찾아서 '배송요청'으로 일괄 변경 + 품목별 상태 반영
    orders = Order.query.filter(Order.order_id.in_(order_ids), Order.status == '결제완료').all()
    
    count = 0
    for o in orders:
        o.status = '배송요청'
        # 해당 주문의 모든 품목에도 배송요청 상태 적용
        for oi in OrderItem.query.filter_by(order_id=o.id, cancelled=False).all():
            oi.item_status = '배송요청'
        # 배송요청 시에는 고객 메시지 발송하지 않음 (기사 픽업 시 배송중 메시지만 발송)
        count += 1

    db.session.commit()
    return jsonify({"success": True, "message": f"{count}건의 배송 요청이 완료되었습니다."})


def _save_delivery_proof_image(file):
    """배송완료 증빙 사진 저장. 반환: URL 또는 None. Cloudinary 설정 시 Cloudinary 사용."""
    if not file or not getattr(file, 'filename', None) or file.filename == '' or not _is_allowed_image_filename(file.filename):
        return None
    try:
        if cloudinary_url:
            upload_res = cloudinary.uploader.upload(
                file,
                folder="basket-uncle/delivery_proof"
            )
            return upload_res.get("secure_url") or upload_res.get("url")
        folder = os.path.join(app.config['UPLOAD_FOLDER'], 'delivery_proof')
        os.makedirs(folder, exist_ok=True)
        ext = os.path.splitext(secure_filename(file.filename))[1].lower() or '.jpg'
        if ext not in ALLOWED_IMAGE_EXTENSIONS:
            ext = '.jpg'
        new_name = f"proof_{now_kst().strftime('%Y%m%d_%H%M%S_%f')}{ext}"
        path = os.path.join(folder, new_name)
        file.save(path)
        return f"/static/uploads/delivery_proof/{new_name}"
    except Exception:
        return None


def _save_delivery_proof_base64(data_url_or_base64):
    """기사 앱에서 보낸 base64 또는 data URL을 파일로 저장. 반환: URL 또는 None. Cloudinary 설정 시 Cloudinary 사용."""
    if not data_url_or_base64 or not isinstance(data_url_or_base64, str):
        return None
    s = data_url_or_base64.strip()
    if s.startswith('data:image'):
        # data:image/jpeg;base64,xxxx
        idx = s.find(',')
        if idx == -1:
            return None
        s = s[idx + 1:]
    try:
        raw = base64.b64decode(s, validate=True)
    except Exception:
        return None
    if len(raw) > 10 * 1024 * 1024:
        return None
    try:
        if cloudinary_url:
            upload_res = cloudinary.uploader.upload(
                BytesIO(raw),
                folder="basket-uncle/delivery_proof"
            )
            return upload_res.get("secure_url") or upload_res.get("url")
        folder = os.path.join(app.config['UPLOAD_FOLDER'], 'delivery_proof')
        os.makedirs(folder, exist_ok=True)
        new_name = f"logi_{now_kst().strftime('%Y%m%d_%H%M%S_%f')}.jpg"
        path = os.path.join(folder, new_name)
        with open(path, 'wb') as f:
            f.write(raw)
        return f"/static/uploads/delivery_proof/{new_name}"
    except Exception:
        return None


@app.route('/api/logi/delivery-in-progress', methods=['POST'])
def api_logi_delivery_in_progress():
    """로지(기사) 픽업(상차) 콜백. order_id(문자열), category 수신 → 해당 품목 배송중 반영 및 고객 메시지 발송."""
    data = request.get_json() or {}
    order_id_str = (data.get('order_id') or '').strip()
    category = (data.get('category') or '').strip()
    if not order_id_str:
        return jsonify({"success": False, "message": "order_id가 필요합니다."}), 400
    order = Order.query.filter_by(order_id=order_id_str).first()
    if not order:
        return jsonify({"success": False, "message": "주문을 찾을 수 없습니다."}), 404
    items = OrderItem.query.filter_by(order_id=order.id, cancelled=False).filter(OrderItem.product_category == category).all()
    if not items:
        return jsonify({"success": False, "message": "해당 카테고리 품목이 없습니다."}), 404
    for oi in items:
        old_status = getattr(oi, 'item_status', None) or '결제완료'
        oi.item_status = '배송중'
        oi.status_message = None
        db.session.add(OrderItemLog(order_id=order.id, order_item_id=oi.id, log_type='item_status', old_value=old_status, new_value='배송중', created_at=now_kst()))
    db.session.commit()
    title, body = get_template_content('delivery_in_progress', order_id=order.order_id)
    if order.user_id:
        send_message(order.user_id, title, body, 'delivery_in_progress', order.id)
        try:
            db.session.commit()
        except Exception:
            db.session.rollback()
    return jsonify({"success": True, "message": "배송중 반영 및 고객 알림 발송 완료."})


@app.route('/api/logi/delivery-complete', methods=['POST'])
def api_logi_delivery_complete():
    """로지(기사) 배송완료 콜백. order_id(문자열), category, photo(base64) 수신 → 품목 배송완료 처리 및 고객 메시지에 사진 포함."""
    data = request.get_json() or {}
    order_id_str = (data.get('order_id') or '').strip()
    category = (data.get('category') or '').strip()
    photo = data.get('photo')
    if not order_id_str:
        return jsonify({"success": False, "message": "order_id가 필요합니다."}), 400
    order = Order.query.filter_by(order_id=order_id_str).first()
    if not order:
        return jsonify({"success": False, "message": "주문을 찾을 수 없습니다."}), 404
    items = OrderItem.query.filter_by(order_id=order.id, cancelled=False).filter(OrderItem.product_category == category).all()
    if not items:
        return jsonify({"success": False, "message": "해당 카테고리 품목이 없습니다."}), 404
    proof_url = _save_delivery_proof_base64(photo) if photo else None
    for oi in items:
        old_status = getattr(oi, 'item_status', None) or '결제완료'
        oi.item_status = '배송완료'
        oi.status_message = None
        if proof_url:
            oi.delivery_proof_image_url = proof_url
        if not oi.cancelled:
            apply_points_on_delivery_complete(oi)
        db.session.add(OrderItemLog(order_id=order.id, order_item_id=oi.id, log_type='item_status', old_value=old_status, new_value='배송완료', created_at=now_kst()))
    db.session.commit()
    # ① 자체 배송완료 메시지: 앱 내 쪽지 + 푸시 (카카오 알림톡과 별도로 항상 발송)
    message_image_url = (proof_url if (proof_url and proof_url.startswith("http")) else (request.url_root.rstrip("/") + proof_url) if proof_url else None)
    title, body = get_template_content('delivery_complete', order_id=order.order_id)
    if order.user_id:
        try:
            send_message(order.user_id, title, body, 'delivery_complete', order.id, image_url=message_image_url)
            db.session.commit()
        except Exception:
            db.session.rollback()
    # ② 카카오 알림톡 (기존대로 유지)
    try:
        extra_vars = {}
        if proof_url:
            full_url = proof_url if proof_url.startswith("http") else request.url_root.rstrip("/") + proof_url
            extra_vars["#{사진링크}"] = full_url
        send_alimtalk_order_event('delivery_complete', order.customer_phone, order.customer_name, order.order_id, **extra_vars)
    except Exception:
        pass
    return jsonify({"success": True, "message": "배송완료 처리 및 고객 알림 발송 완료."})


@login_required
def admin_order_item_status():
    """관리자: 품목별 상태 적용 (품절취소·배송지연·배송중·배송완료 등). 배송완료 시 첨부 이미지 있으면 고객 메시지에 포함."""
    if not (current_user.is_admin or Category.query.filter_by(manager_email=current_user.email).first()):
        return jsonify({"success": False, "message": "권한이 없습니다."}), 403
    if request.content_type and 'multipart/form-data' in request.content_type:
        order_id = request.form.get('order_id', type=int)
        item_id = request.form.get('item_id', type=int)
        item_status = (request.form.get('item_status') or '').strip()
        status_message = (request.form.get('status_message') or '').strip() or None
        delivery_photo = request.files.get('delivery_photo')
    else:
        data = request.get_json() or {}
        order_id = data.get('order_id')
        item_id = data.get('item_id')
        item_status = (data.get('item_status') or '').strip()
        status_message = (data.get('status_message') or '').strip() or None
        delivery_photo = None
    if not order_id or not item_id or not item_status:
        return jsonify({"success": False, "message": "order_id, item_id, item_status가 필요합니다."})
    order = Order.query.get(order_id)
    oi = OrderItem.query.filter_by(id=item_id, order_id=order_id).first()
    if not order or not oi:
        return jsonify({"success": False, "message": "주문 또는 품목을 찾을 수 없습니다."})
    # 카테고리 매니저는 자기 카테고리 품목만
    if not current_user.is_admin and oi.product_category not in [c.name for c in Category.query.filter_by(manager_email=current_user.email).all()]:
        return jsonify({"success": False, "message": "해당 카테고리 관리 권한이 없습니다."}), 403
    allowed = ('결제완료', '배송요청', '배송중', '배송완료', '품절취소', '배송지연', '부분취소')
    if item_status not in allowed:
        return jsonify({"success": False, "message": f"item_status는 {allowed} 중 하나여야 합니다."})

    old_item_status = getattr(oi, 'item_status', None) or '결제완료'
    if item_status == '품절취소':
        if oi.cancelled:
            return jsonify({"success": False, "message": "이미 취소된 품목입니다."})
        cancel_amount = oi.price * oi.quantity
        tax_free_cancel = (oi.price * oi.quantity) if (oi.tax_type == '면세') else 0
        if order.payment_key and cancel_amount > 0:
            url = f"https://api.tosspayments.com/v1/payments/{order.payment_key}/cancel"
            body = {"cancelAmount": cancel_amount, "cancelReason": "품절로 인한 부분 취소"}
            if tax_free_cancel:
                body["taxFreeAmount"] = tax_free_cancel
            res = requests.post(url, json=body, headers=_toss_cancel_headers(f"cancel-{order.id}-item-{oi.id}-out"), timeout=30)
            if res.status_code not in (200, 201):
                try:
                    err = res.json()
                    return jsonify({"success": False, "message": err.get("message", "환불 요청 실패")})
                except Exception:
                    return jsonify({"success": False, "message": "환불 요청 실패"})
        oi.cancelled = True
        oi.item_status = '품절취소'
        oi.status_message = status_message or "품절로 인한 부분 취소"
        p = Product.query.get(oi.product_id)
        if p:
            p.stock += oi.quantity
        _recalc_order_from_items(order)
        title, body = get_template_content('out_of_stock', order_id=order.order_id)
        send_message(order.user_id, title, body, 'out_of_stock', order.id)
    else:
        oi.item_status = item_status
        oi.status_message = status_message
        if item_status == '배송완료' and delivery_photo:
            proof_url = _save_delivery_proof_image(delivery_photo)
            if proof_url:
                oi.delivery_proof_image_url = proof_url
        if not oi.cancelled and item_status == '배송완료':
            apply_points_on_delivery_complete(oi)  # 정산번호(sales_amount) 기준 포인트 적립 (1회만)

    db.session.add(OrderItemLog(order_id=order_id, order_item_id=item_id, log_type='item_status', old_value=old_item_status, new_value=item_status, created_at=now_kst()))
    db.session.commit()
    # 배송 상태 변경 시 회원에게 자동 메시지 (배송완료 시 기사 사진 있으면 첨부)
    # 배송요청 시 고객 메시지 발송 안 함. 배송중 메시지는 기사 픽업 시에만 POST /api/logi/delivery-in-progress 로 발송.
    if item_status in ('배송완료', '배송지연'):
        if item_status == '배송완료':
            title, body = get_template_content('delivery_complete', order_id=order.order_id)
            proof_url = getattr(oi, 'delivery_proof_image_url', None) or None
            send_message(order.user_id, title, body, 'delivery_complete', order.id, image_url=proof_url)
            try:
                extra_vars = {}
                if proof_url:
                    full_url = request.url_root.rstrip('/') + proof_url
                    extra_vars["#{사진링크}"] = full_url
                send_alimtalk_order_event('delivery_complete', order.customer_phone, order.customer_name, order.order_id, **extra_vars)
            except Exception:
                pass
        elif item_status == '배송지연':
            title, body = get_template_content('delivery_delayed', order_id=order.order_id)
            send_message(order.user_id, title, body, 'delivery_delayed', order.id)
        db.session.commit()
    return jsonify({"success": True, "message": f"품목 상태가 '{item_status}'(으)로 적용되었습니다."})


