        for mc in rows:
            u = User.query.get(mc.user_id) if mc.user_id else None
            ord_obj = Order.query.get(mc.order_id) if mc.order_id else None
            order_display = (ord_obj.order_id if ord_obj and getattr(ord_obj, 'order_id', None) else str(mc.order_id))
