    if tab == 'utm' and is_master:
        # 주문 기준: utm_source별 주문 수, 매출, 구매자 수(결제 완료 주문의 distinct user_id)
        from sqlalchemy import distinct
        order_stats = db.session.query(
            Order.utm_source,
            db.func.count(Order.id).label('order_count'),
            db.func.coalesce(db.func.sum(Order.total_price), 0).label('revenue'),
            db.func.count(distinct(Order.user_id)).label('buyer_count')
        ).filter(Order.status != '결제취소').group_by(Order.utm_source).all()
        # 회원가입 수: User.utm_source별
        signup_counts = db.session.query(
            User.utm_source,
            db.func.count(User.id).label('signup_count')
        ).group_by(User.utm_source).all()
        signup_map = {(r.utm_source or '').strip() or '직접/기타': r.signup_count for r in signup_counts}
        # 소스 키 통일 (None/빈값 → 직접/기타)
        def _src(s):
            return (s or '').strip() or '직접/기타'
        utm_aggregates = [
            {
                'source': _src(r.utm_source),
                'order_count': r.order_count,
                'revenue': int(r.revenue or 0),
                'buyer_count': r.buyer_count or 0,
                'signup_count': signup_map.get(_src(r.utm_source), 0)
            }
            for r in order_stats
        ]
        # 유저는 가입만 하고 주문 안 한 소스도 표시
        for usrc, cnt in signup_map.items():
            if not any(a['source'] == usrc for a in utm_aggregates):
                utm_aggregates.append({'source': usrc, 'order_count': 0, 'revenue': 0, 'buyer_count': 0, 'signup_count': cnt})
        utm_aggregates.sort(key=lambda x: (-x['revenue'], -x['order_count']))
