@login_required
def admin_product_bulk_upload_template():
    """상품 엑셀 업로드용 양식 다운로드. 대표이미지: 품명+접미사_1, 상세이미지: 품명+접미사_2 ~ _10."""
    if not current_user.is_admin:
        return redirect('/')
    columns = [
        '카테고리', '상품명', 'Short Intro', '상세문구', '배송', '가격', '규격', '공급가', '재고',
        '마감일시', '재고초기화시각', '초기화수량', '대표이미지파일명', '상세이미지파일명'
    ]
    df = pd.DataFrame(columns=columns)
    df.loc[0] = [
        '가공식품', '간장 오리주물럭 300g', '맵지 않아 온 가족이 즐기는 단짠단짠의 정석!',
        '주문 마감당일 오후 배송됩니다!', '+1일', 5900, '300g', 5000, 30,
        '2026-03-02,23:59', '', 30,
        '간장 오리주물럭 300g01_1', '간장 오리주물럭 300g02_2'
    ]
    out = BytesIO()
    with pd.ExcelWriter(out, engine='openpyxl') as w:
        df.to_excel(w, index=False)
    out.seek(0)
    return send_file(out, mimetype='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', download_name='상품_대량등록_양식.xlsx', as_attachment=True)


def _bulk_safe_image_filename(filename):
    """대량등록용: 경로 제거 후 파일명만 반환. 엑셀에서 그대로 쓸 수 있게 한글 등 유지."""
    if not filename or not isinstance(filename, str):
        return None
    name = os.path.basename(filename).strip()
    for c in '\\/:*?"<>|':
        name = name.replace(c, '_')
    if not name:
        return None
    ext = os.path.splitext(name)[1].lower()
    if ext not in ALLOWED_IMAGE_EXTENSIONS:
        return None
    return name


@login_required
def admin_bulk_upload_images():
    """대량등록용 이미지를 static/uploads/에 저장. 엑셀에서 파일명 그대로 참조 가능."""
    if not current_user.is_admin:
        return redirect('/')
    if request.method != 'POST':
        return redirect('/admin?tab=bulk_register')
    files = request.files.getlist('images') or request.files.getlist('images[]')
    upload_dir = os.path.join(app.root_path, 'static', 'uploads')
    os.makedirs(upload_dir, exist_ok=True)
    saved = []
    skipped = 0
    for f in files:
        if not f or not getattr(f, 'filename', None) or (f.filename or '').strip() == '':
            continue
        safe_name = _bulk_safe_image_filename(f.filename)
        if not safe_name:
            continue
        try:
            path = os.path.join(upload_dir, safe_name)
            if os.path.isfile(path):
                skipped += 1
                continue  # 같은 이름 이미 있으면 건너뜀
            if getattr(f, 'stream', None) and hasattr(f.stream, 'seek'):
                try:
                    f.stream.seek(0)
                except Exception:
                    pass
            data = f.read()
            if not data:
                continue
            with open(path, 'wb') as out:
                out.write(data)
            saved.append(safe_name)
        except Exception as e:
            flash(f"이미지 저장 실패 ({f.filename}): {str(e)}")
    if saved:
        flash(f"{len(saved)}개 이미지가 static/uploads/에 저장되었습니다. 엑셀의 대표·상세이미지파일명에 위 파일명을 그대로 입력하세요.")
    elif skipped:
        flash(f"같은 이름의 파일이 이미 있어 {skipped}개는 건너뛰었습니다. 새 파일만 선택해 주세요.")
    else:
        flash("저장된 이미지가 없습니다. jpg, png, gif, webp 파일을 선택해 주세요.")
    return redirect('/admin?tab=bulk_register')


@login_required
def admin_upload_delete():
    """static/uploads/ 안의 이미지 파일 1개 삭제. 관리자 전용. POST로 filename 전달."""
    if not current_user.is_admin:
        return redirect('/')
    if request.method != 'POST':
        return redirect('/admin?tab=bulk_register')
    filename = (request.form.get('filename') or request.args.get('filename') or '').strip()
    if not filename:
        flash("삭제할 파일명이 없습니다.")
        return redirect('/admin?tab=bulk_register')
    if '..' in filename or '/' in filename or '\\' in filename or os.path.basename(filename) != filename:
        flash("잘못된 파일명입니다.")
        return redirect('/admin?tab=bulk_register')
    upload_dir = os.path.join(app.root_path, 'static', 'uploads')
    path = os.path.join(upload_dir, filename)
    try:
        if os.path.isfile(path) and os.path.realpath(path).startswith(os.path.realpath(upload_dir)):
            os.remove(path)
            flash(f"이미지가 삭제되었습니다: {filename}")
        else:
            flash(f"파일을 찾을 수 없거나 삭제할 수 없습니다: {filename}")
    except OSError as e:
        flash(f"삭제 실패: {e}")
    return redirect('/admin?tab=bulk_register')


@login_required
def admin_upload_delete_all():
    """static/uploads/ 루트에 있는 이미지 파일 전부 삭제. 하위 폴더(reviews, board 등)는 건드리지 않음."""
    if not current_user.is_admin:
        return redirect('/')
    if request.method != 'POST':
        return redirect('/admin?tab=bulk_register')
    upload_dir = os.path.join(app.root_path, 'static', 'uploads')
    real_upload = os.path.realpath(upload_dir)
    count = 0
    try:
        if not os.path.isdir(upload_dir):
            flash("업로드 폴더가 없습니다.")
            return redirect('/admin?tab=bulk_register')
        exts = ('.jpg', '.jpeg', '.png', '.gif', '.webp')
        for fn in os.listdir(upload_dir):
            if fn.startswith('.'):
                continue
            path = os.path.join(upload_dir, fn)
            if not os.path.isfile(path):
                continue
            if os.path.realpath(path).startswith(real_upload) and os.path.splitext(fn)[1].lower() in exts:
                os.remove(path)
                count += 1
        flash(f"static/uploads/ 이미지 {count}개를 삭제했습니다.")
    except OSError as e:
        flash(f"전체 삭제 중 오류: {e}")
    return redirect('/admin?tab=bulk_register')


@login_required
def admin_product_bulk_upload():
    """엑셀 파일만 업로드. 이미지는 서버 static/uploads/에 두고 엑셀에는 파일명만 입력."""
    if not current_user.is_admin:
        return redirect('/')
    file = request.files.get('excel_file')
    if not file or file.filename == '':
        return redirect('/admin?tab=bulk_register')
    fn = (file.filename or '').strip().lower()
    if not (fn.endswith('.xlsx') or fn.endswith('.xls')):
        flash("엑셀 파일(.xlsx 또는 .xls)만 업로드 가능합니다.")
        return redirect('/admin?tab=bulk_register')
    try:
        df = pd.read_excel(file)
        df.columns = df.columns.astype(str).str.strip()
        required = ['카테고리', '상품명', '가격']
        if not all(c in df.columns for c in required):
            flash("엑셀 헤더에 필수 컬럼이 없습니다. 필수: 카테고리, 상품명, 가격")
            return redirect('/admin?tab=bulk_register')
        upload_dir = os.path.join(app.root_path, 'static', 'uploads')
        os.makedirs(upload_dir, exist_ok=True)
        if not Category.query.first():
            flash("등록된 카테고리가 없습니다. 먼저 [카테고리] 탭에서 카테고리를 추가한 뒤 대량등록을 진행해 주세요.")
            return redirect('/admin?tab=bulk_register')
        count = 0
        missing_images = []  # (상품명, 대표파일명, [상세파일명...]) 서버에 없어서 매칭 안 된 경우
        for idx, row in df.iterrows():
            cat_name = _cell_str(row.get('카테고리', ''))
            if not cat_name or cat_name.startswith('('):
                continue
            cat = Category.query.filter_by(name=cat_name).first()
            if not cat:
                continue
            name_val = _cell_str(row.get('상품명', ''))
            if not name_val or name_val.startswith('('):
                continue
            name_val = name_val.strip().replace('\ufeff', '').strip()
            name_val = _bulk_normalize_name(name_val)
            try:
                price_val = int(float(row.get('가격', 0)))
            except (ValueError, TypeError):
                price_val = 0
            if price_val < 0:
                continue
            badge = _cell_str(row.get('Short Intro', ''))
            origin = _cell_str(row.get('상세문구', ''))
            description = _cell_str(row.get('배송', '')) or '+1일'
            spec = _cell_str(row.get('규격', ''))
            supply_price = _cell_int(row.get('공급가'))
            stock = _cell_int(row.get('재고'))
            if stock is None or stock < 0:
                stock = 50
            deadline_val = _cell_str(row.get('마감일시', ''))
            deadline = None
            if deadline_val:
                deadline_val = deadline_val.strip().replace(',', ' ')[:19]
                for fmt in ('%Y-%m-%d %H:%M', '%Y-%m-%d %H:%M:%S', '%Y-%m-%d'):
                    try:
                        deadline = datetime.strptime(deadline_val.strip()[:19], fmt)
                        break
                    except ValueError:
                        continue
            reset_time = _cell_str(row.get('재고초기화시각', ''))[:5] or None
            reset_to_q = _cell_int(row.get('초기화수량'))
            tax_type = _cell_str(row.get('세금', '')) or (cat.tax_type or '과세')
            if tax_type not in ('과세', '면세'):
                tax_type = '과세'
            image_url = ""
            detail_image_url = ""
            missing_main = None
            missing_details = []
            main_img_raw = _cell_str(row.get('대표이미지파일명', '')) or _cell_str(row.get('이미지파일명', ''))
            image_url = (_bulk_try_copy_from_absolute_path(main_img_raw, upload_dir) if main_img_raw else None) or ""
            if not image_url:
                if not main_img_raw or _bulk_is_placeholder_image(main_img_raw):
                    for suffix in ("1", "_1"):
                        found = _bulk_find_upload_by_basename(upload_dir, name_val + suffix)
                        if found:
                            image_url = f"/static/uploads/{found.replace(chr(92), '/')}"
                            break
                    if not image_url:
                        name_no_spaces = name_val.replace(" ", "")
                        if name_no_spaces != name_val:
                            for suffix in ("1", "_1"):
                                found = _bulk_find_upload_by_basename(upload_dir, name_no_spaces + suffix)
                                if found:
                                    image_url = f"/static/uploads/{found.replace(chr(92), '/')}"
                                    break
                    if not image_url:
                        for base in (name_val + "1", name_val + "_1", name_val.replace(" ", "") + "1", name_val.replace(" ", "") + "_1"):
                            found = _bulk_find_upload_by_basename_fuzzy(upload_dir, base)
                            if found:
                                image_url = f"/static/uploads/{found.replace(chr(92), '/')}"
                                break
                if not image_url:
                    main_img = _bulk_image_filename_only(main_img_raw)
                    if main_img and not _bulk_is_placeholder_image(main_img):
                        found = _bulk_find_upload_file(upload_dir, main_img)
                        if found:
                            image_url = f"/static/uploads/{found.replace(chr(92), '/')}"
                        else:
                            missing_main = main_img
            path_for_same_folder = (main_img_raw or '').strip().strip('"').strip("'").strip()
            is_abs = path_for_same_folder and ((len(path_for_same_folder) >= 2 and path_for_same_folder[1] == ':') or path_for_same_folder.startswith('/') or '\\' in path_for_same_folder)
            if is_abs and os.path.isfile(path_for_same_folder):
                detail_from_folder = _bulk_copy_detail_2_to_10_from_same_folder(path_for_same_folder, upload_dir)
                if detail_from_folder:
                    detail_image_url = ",".join(detail_from_folder)
            if not detail_image_url:
                detail_imgs_raw = _cell_str(row.get('상세이미지파일명', ''))
                if detail_imgs_raw and not _bulk_is_placeholder_image(detail_imgs_raw):
                    parts = [p.strip().lstrip('/').strip('"').strip("'") for p in detail_imgs_raw.split(',') if p.strip() and not _bulk_is_placeholder_image(p.strip())]
                    detail_parts = []
                    for p in parts:
                        u = _bulk_try_copy_from_absolute_path(p, upload_dir)
                        if u:
                            detail_parts.append(u)
                        else:
                            fn_img = _bulk_image_filename_only(p)
                            if fn_img:
                                found = _bulk_find_upload_file(upload_dir, fn_img)
                                if found:
                                    detail_parts.append(f"/static/uploads/{found.replace(chr(92), '/')}")
                                else:
                                    missing_details.append(fn_img)
                    if detail_parts:
                        detail_image_url = ",".join(detail_parts)
                else:
                    detail_parts = []
                    for suffix in ("2", "3", "4", "5", "6", "7", "8", "9", "10"):
                        found = _bulk_find_upload_by_basename(upload_dir, name_val + suffix)
                        if not found and suffix.isdigit():
                            found = _bulk_find_upload_by_basename(upload_dir, name_val + "_" + suffix)
                        if not found:
                            name_no_spaces = name_val.replace(" ", "")
                            if name_no_spaces != name_val:
                                found = _bulk_find_upload_by_basename(upload_dir, name_no_spaces + suffix)
                                if not found and suffix.isdigit():
                                    found = _bulk_find_upload_by_basename(upload_dir, name_no_spaces + "_" + suffix)
                        if not found:
                            for base in (name_val + suffix, name_val + "_" + suffix, name_val.replace(" ", "") + suffix, name_val.replace(" ", "") + "_" + suffix):
                                found = _bulk_find_upload_by_basename_fuzzy(upload_dir, base)
                                if found:
                                    break
                        if found:
                            detail_parts.append(f"/static/uploads/{found.replace(chr(92), '/')}")
                    if detail_parts:
                        detail_image_url = ",".join(detail_parts)
            if missing_main or missing_details:
                missing_images.append((name_val, missing_main or '', list(missing_details)))
            if not detail_image_url:
                detail_image_url = image_url or ""
            new_p = Product(
                category=cat_name,
                name=name_val,
                description=description,
                price=price_val,
                supply_price=supply_price,
                spec=spec or "",
                origin=origin or "",
                farmer="바구니삼촌",
                image_url=image_url,
                detail_image_url=detail_image_url,
                stock=stock,
                deadline=deadline,
                reset_time=reset_time,
                reset_to_quantity=reset_to_q,
                badge=badge or "",
                tax_type=tax_type,
                is_active=True,
            )
            db.session.add(new_p)
            count += 1
        db.session.commit()
        flash(f"{count}개 상품이 등록되었습니다.")
        if missing_images:
            lines = []
            for name, main_f, detail_fs in missing_images:
                parts = []
                if main_f:
                    parts.append(f"대표:{main_f}")
                if detail_fs:
                    parts.append(f"상세:{','.join(detail_fs)}")
                lines.append(f"{name} ({'; '.join(parts)})")
            n = len(missing_images)
            flash(f"이미지가 없는 {n}건: {' | '.join(lines[:10])}{' ...' if len(lines) > 10 else ''}")
            flash("→ 엑셀의 대표·상세이미지파일명을 '저장된 이미지 목록'에 보이는 파일명과 똑같이 쓰거나, 칸을 비우면 상품명+1·상품명+2 패턴으로 찾습니다. 공백·오타·인코딩이 다르면 매칭되지 않습니다.")
        return redirect('/admin?tab=bulk_register')
    except Exception as e:
        db.session.rollback()
        flash(f"업로드 실패: {str(e)}")
        return redirect('/admin?tab=bulk_register')
    except BaseException as e:
        db.session.rollback()
        flash(f"업로드 중 오류가 발생했습니다: {str(e)}")
        return redirect('/admin?tab=bulk_register')


def _bulk_normalize_name(s):
    """엑셀에서 읽은 상품명·파일명 정규화: BOM·유니코드 공백 제거, NFC 정규화. 매칭 실패 방지용."""
    if not s or not isinstance(s, str):
        return s if s else ""
    t = s.replace("\ufeff", "").strip()
    for c in ("\u200b", "\u200c", "\u200d", "\ufeff", "\u00a0"):
        t = t.replace(c, " ")
    t = " ".join(t.split())
    return unicodedata.normalize("NFC", t) if t else ""


def _bulk_normalize_for_fuzzy_match(s):
    """파일명 비교용 퍼지 키: 공백·._- 제거, 소문자, NFC. '고추장 오돌뼈 200g1' == '고추장오돌뼈 200g 1' 등."""
    if not s or not isinstance(s, str):
        return ""
    t = unicodedata.normalize("NFC", s.strip().lower())
    for c in " \t._-\u00a0\u200b\u200c\u200d\ufeff":
        t = t.replace(c, "")
    return t


def _bulk_is_placeholder_image(s):
    """엑셀 양식 placeholder(파일명.jpg 등)이면 True. 실제 파일명만 URL에 쓰기 위해."""
    if not s or not isinstance(s, str):
        return True
    t = s.strip().lower()
    if not t:
        return True
    if t.startswith('(') and ')' in t:
        return True
    if '파일명' in t or 'file' in t and 'example' in t:
        return True
    if t in ('(파일명.jpg)', '(파일명)', '파일명.jpg', '파일명', '(a.jpg,b.jpg)', '(예: apple.jpg)'):
        return True
    return False


def _bulk_image_filename_only(s):
    """엑셀에 전체 경로나 따옴표가 들어와도 URL에는 파일명만 사용. 예: \"C:/Users/.../1.jpg\" -> 1.jpg"""
    if not s or not isinstance(s, str):
        return ""
    t = s.strip().strip('"').strip("'").strip()
    if not t:
        return ""
    if '/' in t or '\\' in t:
        return os.path.basename(t)
    return t


def _bulk_find_upload_file(upload_dir, filename):
    """upload_dir 안에 filename과 일치하는 파일이 있으면 URL용 파일명 반환, 없으면 None.
    Windows에서는 대소문자 구분 없이 매칭. NFC/NFD·퍼지(공백·기호 무시) 매칭 시도."""
    if not filename or not isinstance(filename, str):
        return None
    name = filename.strip().strip('"').strip("'").replace("\\", "/").lstrip("/")
    if "/" in name:
        name = os.path.basename(name)
    name = _bulk_normalize_name(name) or name.strip()
    if not name:
        return None
    for candidate in (name, unicodedata.normalize("NFC", name), unicodedata.normalize("NFD", name)):
        direct = os.path.join(upload_dir, candidate)
        if os.path.isfile(direct):
            return candidate
    want_low = name.lower()
    want_nfc = unicodedata.normalize("NFC", name).lower()
    want_fuzzy = _bulk_normalize_for_fuzzy_match(name)
    try:
        for fn in os.listdir(upload_dir):
            p = os.path.join(upload_dir, fn)
            if not os.path.isfile(p):
                continue
            if fn.lower() == want_low or fn.lower() == want_nfc:
                return fn
            if want_fuzzy and _bulk_normalize_for_fuzzy_match(fn) == want_fuzzy:
                return fn
    except OSError:
        pass
    return None


def _bulk_find_upload_by_basename(upload_dir, base_without_ext):
    """확장자 없이 base 이름만 주면, .jpg/.jpeg/.png/.webp/.gif 순으로 찾아서 첫 매칭 파일명 반환.
    상품명+숫자 패턴(예: 간장 오리주물럭 300g1, 간장 오리주물럭 300g2) 인식용."""
    if not base_without_ext or not isinstance(base_without_ext, str):
        return None
    base = base_without_ext.strip()
    if not base:
        return None
    for ext in ('.jpg', '.jpeg', '.png', '.webp', '.gif'):
        found = _bulk_find_upload_file(upload_dir, base + ext)
        if found:
            return found
    return None


def _bulk_find_upload_by_basename_fuzzy(upload_dir, base_without_ext):
    """공백·._- 차이 무시하고 퍼지 매칭. 상품명+숫자 형태가 파일명과 조금 달라도 매칭."""
    if not base_without_ext or not isinstance(base_without_ext, str):
        return None
    want = _bulk_normalize_for_fuzzy_match(base_without_ext)
    if not want:
        return None
    exts = ('.jpg', '.jpeg', '.png', '.webp', '.gif')
    try:
        for fn in os.listdir(upload_dir):
            p = os.path.join(upload_dir, fn)
            if not os.path.isfile(p):
                continue
            base, ext = os.path.splitext(fn)
            if ext.lower() not in exts:
                continue
            if _bulk_normalize_for_fuzzy_match(base) == want:
                return fn
    except OSError:
        pass
    return None


def _bulk_try_copy_from_absolute_path(raw_value, upload_dir):
    """엑셀 셀에 로컬 전체 경로가 있으면 Cloudinary 또는 upload_dir에 복사하고 URL 반환. 없거나 실패 시 None."""
    if not raw_value or not isinstance(raw_value, str):
        return None
    import shutil
    path = raw_value.strip().strip('"').strip("'").strip()
    if not path:
        return None
    is_absolute = (len(path) >= 2 and path[1] == ':') or path.startswith('/') or path.startswith('\\') or ('\\' in path and path[0].isalpha())
    if not is_absolute or not os.path.isfile(path):
        return None
    try:
        if cloudinary_url:
            with open(path, 'rb') as fh:
                file_bytes = fh.read()
            res = cloudinary.uploader.upload(file_bytes, folder="basket-uncle/main")
            url = res.get("secure_url") or res.get("url")
            if url and "/upload/" in url:
                url = url.replace("/upload/", "/upload/w_800,h_800,c_fill/")
            return url
        ext = (os.path.splitext(path)[1] or '.jpg').lower()
        if ext not in ('.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp'):
            ext = '.jpg'
        new_name = f"bulk_{now_kst().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}{ext}"
        dest = os.path.join(os.path.abspath(upload_dir), new_name)
        shutil.copy2(path, dest)
        if os.path.isfile(dest):
            return f"/static/uploads/{new_name}"
    except Exception as e:
        print(f"[_bulk_try_copy_from_absolute_path] ERROR: {e}")
    return None


def _bulk_copy_detail_2_to_10_from_same_folder(main_absolute_path, upload_dir):
    """대표이미지 전체 경로 기준으로 같은 폴더의 상세이미지(2~10번)를 Cloudinary 또는 로컬에 복사.

    - 파일명이 1.jpg, 2.jpg, ... 10.jpg 형태인 경우
    - 또는 '상품명+접미사_숫자' 형식(예: 품명01_1=대표, 품명02_2~품명10_10=상세)인 경우
      → 접미사에서 마지막 숫자(_1~_10)를 인덱스로 사용
    """
    if not main_absolute_path or not isinstance(main_absolute_path, str):
        return []
    import shutil
    import re
    path = main_absolute_path.strip().strip('"').strip("'").strip()
    if not path or not os.path.isfile(path):
        return []
    dir_path = os.path.dirname(path)
    upload_abs = os.path.abspath(upload_dir)
    os.makedirs(upload_abs, exist_ok=True)
    exts = ('.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp')

    # 디렉토리 내 이미지 파일들을 스캔하면서 "인덱스 번호"를 추출해 2~10번만 상세로 사용
    by_idx = {}
    try:
        for f in os.listdir(dir_path):
            base, ext = os.path.splitext(f)
            if ext.lower() not in exts:
                continue
            full_path = os.path.join(dir_path, f)
            if not os.path.isfile(full_path):
                continue
            # 파일명에서 마지막 숫자 덩어리를 인덱스로 사용 (없으면 1로 간주)
            m = re.search(r'(\d+)\s*$', base.strip())
            try:
                idx = int(m.group(1)) if m else 1
            except Exception:
                idx = 1
            if 1 <= idx <= 10:
                by_idx[idx] = full_path
    except Exception as e:
        print(f"[_bulk_copy_detail] scan ERROR: {e}")
        return []

    urls = []
    for num in range(2, 11):
        candidate = by_idx.get(num)
        if not candidate:
            continue
        try:
            if cloudinary_url:
                with open(candidate, 'rb') as fh:
                    file_bytes = fh.read()
                res = cloudinary.uploader.upload(file_bytes, folder="basket-uncle/detail")
                url = res.get("secure_url") or res.get("url")
                if url:
                    if "/upload/" in url:
                        url = url.replace("/upload/", "/upload/w_1200,c_limit/")
                    urls.append(url)
            else:
                ext = os.path.splitext(candidate)[1].lower()
                new_name = f"bulk_{num}_{now_kst().strftime('%Y%m%d_%H%M%S')}_{uuid.uuid4().hex[:8]}{ext}"
                dest = os.path.join(upload_abs, new_name)
                shutil.copy2(candidate, dest)
                if os.path.isfile(dest):
                    urls.append(f"/static/uploads/{new_name}")
        except Exception as e:
            print(f"[_bulk_copy_detail] num={num} ERROR: {e}")
    return urls


def _bulk_collect_images_from_folder(images_root, product_name, upload_dir):
    """images_root(및 하위)에서 상품명과 일치하는 폴더 또는 '상품명+접미사_숫자' 파일을 찾아 수집.
    - 대표이미지: 품명+접미사_1 (예: 간장 오리주물럭 300g01_1.jpg)
    - 상세이미지: 품명+접미사_2 ~ _10 (예: 간장 오리주물럭 300g02_2.jpg)
    폴더 안에 1.jpg~10.jpg가 있는 기존 방식도 지원. 복사 후 URL 반환."""
    import shutil
    import unicodedata
    import re
    IMAGE_EXT = ('.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp')
    main_url = ""
    detail_urls = []

    def norm(s):
        return unicodedata.normalize('NFC', (s or '').strip())

    def norm_for_match(s):
        """비교용: NFC 정규화 후 연속 공백(전각 포함)을 하나의 공백으로."""
        t = unicodedata.normalize('NFC', (s or '').strip())
        t = re.sub(r'[\s\u3000]+', ' ', t)  # 공백·전각공백 등 연속을 하나로
        return t.strip()

    product_name_norm = norm(product_name)
    product_name_match = norm_for_match(product_name)
    if not product_name_norm:
        return main_url, detail_urls

    product_folder = None

    # 1) 우선 "상품명과 같은 폴더"를 찾는 기존 방식
    candidate = os.path.join(images_root, product_name.strip())
    if os.path.isdir(candidate):
        product_folder = candidate
    if not product_folder:
        try:
            for d in os.listdir(images_root):
                if not os.path.isdir(os.path.join(images_root, d)):
                    continue
                dn = norm(d)
                dm = norm_for_match(d)
                if dn == product_name_norm or dm == product_name_match or d.strip() == product_name.strip():
                    product_folder = os.path.join(images_root, d)
                    break
        except Exception:
            pass
    if not product_folder:
        try:
            for root, dirs, _ in os.walk(images_root):
                for d in dirs:
                    dn = norm(d)
                    dm = norm_for_match(d)
                    if dn == product_name_norm or dm == product_name_match or d.strip() == product_name.strip():
                        product_folder = os.path.join(root, d)
                        break
                if product_folder:
                    break
        except Exception:
            pass

    by_num = {}

    if product_folder and os.path.isdir(product_folder):
        # 1-A) 폴더 안에 1.jpg~10.jpg 있는 구조 (기존 방식)
        try:
            for f in os.listdir(product_folder):
                base, ext = os.path.splitext(f)
                if ext.lower() not in IMAGE_EXT:
                    continue
                try:
                    n = int(base.strip())
                    if 1 <= n <= 10:
                        by_num[n] = os.path.join(product_folder, f)
                except ValueError:
                    continue
        except Exception:
            return main_url, detail_urls
    else:
        # 1-B) 폴더가 없고, "상품명+접미사_숫자" 형식의 파일이 images_root(엑셀과 같은 폴더)에 있는 경우
        # 예: 엑셀과 같은 폴더에 "간장 오리주물럭 300g01_1.jpg", "간장 오리주물럭 300g02_2.jpg"
        try:
            for root, _, files in os.walk(images_root):
                for f in files:
                    base, ext = os.path.splitext(f)
                    if ext.lower() not in IMAGE_EXT:
                        continue
                    base_norm = norm_for_match(base)
                    # 패턴: 품명 + (선택 숫자) + _ + 1~10 → 대표/상세 인덱스
                    m = re.search(r'_(\d+)\s*$', base_norm)
                    if not m:
                        continue
                    try:
                        idx = int(m.group(1))
                    except Exception:
                        continue
                    if idx < 1 or idx > 10:
                        continue
                    prefix = base_norm[:m.start()].strip()
                    # 접두사가 상품명으로 시작하는지 확인 (공백/전각 정규화 후)
                    if not prefix.startswith(product_name_match) and not norm_for_match(prefix).startswith(product_name_match):
                        continue
                    by_num[idx] = os.path.join(root, f)
        except Exception:
            return main_url, detail_urls

    if not by_num:
        return main_url, detail_urls

    upload_dir_abs = os.path.abspath(upload_dir)
    os.makedirs(upload_dir_abs, exist_ok=True)
    ts = now_kst().strftime('%Y%m%d_%H%M%S')
    for num in range(1, 11):
        src = by_num.get(num)
        if not src or not os.path.isfile(src):
            continue
        ext = os.path.splitext(src)[1].lower()
        try:
            if cloudinary_url:
                with open(src, 'rb') as fh:
                    file_bytes = fh.read()
                if num == 1:
                    res = cloudinary.uploader.upload(file_bytes, folder="basket-uncle/main")
                    url = res.get("secure_url") or res.get("url") or ""
                    if url and "/upload/" in url:
                        url = url.replace("/upload/", "/upload/w_800,h_800,c_fill/")
                else:
                    res = cloudinary.uploader.upload(file_bytes, folder="basket-uncle/detail")
                    url = res.get("secure_url") or res.get("url") or ""
                    if url and "/upload/" in url:
                        url = url.replace("/upload/", "/upload/w_1200,c_limit/")
            else:
                new_name = f"bulk_{num}_{ts}_{uuid.uuid4().hex[:8]}{ext}"
                dest = os.path.join(upload_dir_abs, new_name)
                shutil.copy2(src, dest)
                if not os.path.isfile(dest):
                    continue
                url = f"/static/uploads/{new_name}"
            if url:
                if num == 1:
                    main_url = url
                else:
                    detail_urls.append(url)
        except Exception as e:
            print(f"[_bulk_collect_images_from_folder] num={num} ERROR: {e}")
            continue
    if not detail_urls and main_url:
        detail_urls = [main_url]
    return main_url, detail_urls


def _cell_str(v):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return ""
    s = str(v).strip()
    return s if s and s.lower() not in ('nan', 'none') else ""


def _cell_int(v):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return None
    try:
        return int(float(v))
    except (ValueError, TypeError):
        return None

