@login_required
def admin_backup_run():
    """관리자: 수동 백업 실행 (SQLite → zip → GitHub Release 또는 로컬)."""
    if not current_user.is_admin:
        return jsonify({"success": False, "message": "권한이 없습니다."}), 403
    ok, msg = run_backup()
    if ok:
        return jsonify({"success": True, "message": msg})
    return jsonify({"success": False, "message": msg}), 500


def admin_backup_cron():
    """외부 cron에서 호출 (한국시간 새벽 4시 등). 쿼리 key=BACKUP_CRON_SECRET 과 일치해야 함."""
    key = (request.args.get("key") or "").strip()
    secret = os.getenv("BACKUP_CRON_SECRET", "").strip()
    if not secret or key != secret:
        return jsonify({"success": False, "message": "Unauthorized"}), 401
    ok, msg = run_backup()
    return jsonify({"success": ok, "message": msg})


@login_required
def admin_review_delete(rid):
    if not (current_user.is_admin or Category.query.filter_by(manager_email=current_user.email).first()):
        return redirect('/')
    r = Review.query.get_or_404(rid)
    if not current_user.is_admin:
        my_cat_ids = [c.id for c in Category.query.filter_by(manager_email=current_user.email).all()]
        if r.category_id not in my_cat_ids:
            flash("해당 리뷰에 대한 삭제 권한이 없습니다.")
            return redirect('/admin?tab=reviews')
    db.session.delete(r)
    db.session.commit()
    flash("리뷰가 삭제되었습니다.")
    return redirect('/admin?tab=reviews')


def admin_board_comment_delete(cid):
    """게시판 댓글 삭제 (관리자 전용). 삭제 후 댓글 관리 탭으로 복귀."""
    if not current_user.is_admin:
        flash("권한이 없습니다.")
        return redirect('/')
    c = BoardComment.query.get_or_404(cid)
    db.session.delete(c)
    db.session.commit()
    flash("댓글이 삭제되었습니다.")
    next_tab = (request.form.get('next_tab') or '').strip() or 'board_comments'
    board_type = (request.form.get('board_type') or '').strip()
    base = url_for('admin_dashboard') + '?tab=' + next_tab
    if board_type in ('restaurant', 'delivery', 'partnership', 'free'):
        return redirect(base + '&board_type=' + board_type)
    return redirect(base)


