# 7-2. 테스트 카테고리 3개 + 가상 상품 10개씩 시드 (전 기능 테스트용)
# --------------------------------------------------------------------------------
def _seed_test_categories_and_products():
    """테스트 카테고리 3개와 카테고리당 가상 상품 10개 생성. 등록 기능 전 필드 활용."""
    now = now_kst()
    today_evening = now.replace(hour=20, minute=0, second=0, microsecond=0)
    tomorrow = (now + timedelta(days=1)).replace(hour=18, minute=0, second=0, microsecond=0)
    categories_data = [
        {"name": "테스트-채소", "description": "테스트용 채소 카테고리 (상품 등록·수정·배지·마감 테스트)", "order": 900},
        {"name": "테스트-과일", "description": "테스트용 과일 카테고리", "order": 901},
        {"name": "테스트-수산", "description": "테스트용 수산 카테고리", "order": 902},
    ]
    for cdata in categories_data:
        if not Category.query.filter_by(name=cdata["name"]).first():
            db.session.add(Category(name=cdata["name"], description=cdata["description"], order=cdata["order"], tax_type="과세"))
    db.session.commit()

    products_data = []
    # 테스트-채소 10종: description(당일/+1/+2), badge(오늘마감/삼촌추천/없음), deadline(오늘/내일/없음), stock 다양
    veg_names = ["청경채 1단", "상추 2종 모둠", "깻잎 1단", "시금치 1단", "브로콜리 1송이", "당근 1kg", "양파 2kg", "대파 3대", "쪽파 1단", "미나리 1단"]
    for i, name in enumerate(veg_names):
        products_data.append({
            "category": "테스트-채소", "name": name, "description": ["당일배송", "+1일", "+2일", "+3일"][i % 4],
            "price": [3500, 4500, 2800, 3200, 2200, 4000, 3500, 1500, 1800, 2500][i],
            "spec": ["1단", "1팩", "1단", "1단", "1송이", "1kg", "2kg", "3대", "1단", "1단"][i],
            "origin": "국산", "farmer": "바구니삼촌", "stock": [5, 10, 20, 15, 30, 50, 40, 99, 10, 8][i],
            "deadline": today_evening if i % 3 == 0 else (tomorrow if i % 3 == 1 else None),
            "badge": ["오늘마감", "삼촌추천", ""][i % 3], "image_url": f"https://placehold.co/400x400/dcfce7/166534?text=V{i+1}",
            "detail_image_url": f"https://placehold.co/600x400/bbf7d0/166534?text={name[:4]}",
        })
    # 테스트-과일 10종
    fruit_names = ["사과 2kg", "배 1.5kg", "포도 1kg", "귤 2kg", "수박 1통", "참외 2kg", "복숭아 1kg", "블루베리 125g", "딸기 500g", "바나나 1kg"]
    for i, name in enumerate(fruit_names):
        products_data.append({
            "category": "테스트-과일", "name": name, "description": ["+1일", "+2일", "당일배송", "+3일"][i % 4],
            "price": [12000, 15000, 8000, 9000, 18000, 14000, 11000, 6500, 12000, 4500][i],
            "spec": ["2kg", "1.5kg", "1kg", "2kg", "1통", "2kg", "1kg", "125g", "500g", "1kg"][i],
            "origin": "국산", "farmer": "바구니삼촌", "stock": [20, 15, 30, 40, 10, 25, 18, 50, 12, 60][i],
            "deadline": tomorrow if i % 2 == 0 else None, "badge": ["삼촌추천", "", "오늘마감"][i % 3],
            "image_url": f"https://placehold.co/400x400/fef3c7/d97706?text=F{i+1}",
            "detail_image_url": f"https://placehold.co/600x400/fde68a/d97706?text={name[:4]}",
        })
    # 테스트-수산 10종
    fish_names = ["고등어 2마리", "갈치 1kg", "동태 1마리", "새우 300g", "오징어 1마리", "문어 1마리", "연어 200g", "참치캔 3캔", "멸치 100g", "김 10장"]
    for i, name in enumerate(fish_names):
        products_data.append({
            "category": "테스트-수산", "name": name, "description": ["+1일", "+2일", "+3일", "당일배송"][i % 4],
            "price": [8000, 12000, 6500, 15000, 9000, 18000, 7000, 4500, 3500, 4000][i],
            "spec": ["2마리", "1kg", "1마리", "300g", "1마리", "1마리", "200g", "3캔", "100g", "10장"][i],
            "origin": "국산/수입", "farmer": "바구니삼촌", "stock": [10, 8, 25, 15, 12, 5, 30, 50, 40, 20][i],
            "deadline": today_evening if i % 4 == 0 else (tomorrow if i % 4 == 1 else None),
            "badge": ["", "오늘마감", "삼촌추천", ""][i % 4],
            "image_url": f"https://placehold.co/400x400/dbeafe/1d4ed8?text=S{i+1}",
            "detail_image_url": f"https://placehold.co/600x400/bfdbfe/1d4ed8?text={name[:4]}",
        })

    # 마감시간 기능 테스트용 가상 상품: 현재시각 + 15분 마감 (테스트-채소에 1종)
    deadline_test_at = now + timedelta(minutes=15)
    if not Product.query.filter_by(category="테스트-채소", name="마감테스트-가상상품").first():
        products_data.append({
            "category": "테스트-채소", "name": "마감테스트-가상상품", "description": "당일배송",
            "price": 1000, "spec": "1개", "origin": "마감 카운트다운 테스트용", "farmer": "바구니삼촌",
            "stock": 99, "deadline": deadline_test_at, "badge": "오늘마감",
            "image_url": "https://placehold.co/400x400/fecaca/dc2626?text=마감테스트",
            "detail_image_url": "https://placehold.co/600x400/fecaca/dc2626?text=마감테스트",
        })

    created = 0
    for pdata in products_data:
        exists = Product.query.filter_by(category=pdata["category"], name=pdata["name"]).first()
        if not exists:
            p = Product(
                category=pdata["category"], name=pdata["name"], description=pdata["description"],
                price=pdata["price"], spec=pdata["spec"], origin=pdata["origin"], farmer=pdata["farmer"],
                stock=pdata["stock"], deadline=pdata["deadline"], badge=pdata.get("badge", ""),
                image_url=pdata["image_url"], detail_image_url=pdata.get("detail_image_url", pdata["image_url"]),
                is_active=True, tax_type="과세"
            )
            db.session.add(p)
            created += 1
    db.session.commit()
    return created


def _seed_virtual_reviews_per_product(count_per_product=10):
    """상품별 가상 구매 후기 count_per_product개씩 생성. order_id는 가상 고유값(음수) 사용.
    랜덤 조합으로 실제 사용자 후기처럼 다양하게 생성 (문장·이름·사진 유무 랜덤)."""
    # 실제 사용자처럼 다양한 문장 조합 (앞·뒤·중간 랜덤)
    review_starts = [
        "맛있고 신선해요.", "배송 빨라서 좋았어요.", "생각보다 양 많고", "친구 추천으로 처음 주문했는데",
        "포장 꼼꼼하고 상태 좋았어요.", "맛이 좋아서", "당일 받아서", "가격 대비 퀄리티",
        "신선하고 맛있어요.", "서비스도 좋고", "품질 대만족이에요.", "다음에도 여기서",
        "재구매 의사 100%", "직접 먹어보니", "예상보다 훨씬 좋아요.", "아이들도 잘 먹어요.",
        "선물로 보냈는데 반응 좋았어요.", "냉장고에 넣어두고 먹기 좋아요.", "요리해 먹었더니",
        "저렴한데 퀄 좋아요.", "다른 곳이랑 비교해도 여기가 최고.", "배송도 빠르고",
    ]
    review_mids = [
        "", " 두 번 구매했어요.", " 가족이 다 좋아해요.", " 다음에 또 시킬게요.",
        " 포장 상태 완벽했어요.", " 맛집에서 먹는 것 같아요.", " 강추합니다.",
    ]
    review_ends = [
        " 다음에도 주문할게요!", " 품질도 만족합니다.", " 가성비 좋아요.", " 대만족입니다.",
        " 추천합니다.", " 자주 시켜먹을 것 같아요.", " 너무 만족스러워요.", " 감사해요.",
        " 재주문 의사 있습니다.", " 감사합니다.", " 별 다섯 개요.", " 꼭 다시 살게요.",
        " 주변에도 추천했어요.", " 만족해요.", " 좋았어요.", " 감동이에요.",
    ]
    # 한 문장만 쓰는 후기 (짧은 스타일)
    review_one_liners = [
        "맛있어요 재구매 예정입니다.", "배송 빠르고 신선해요.", "가성비 최고.",
        "친구한테도 추천했어요.", "포장 꼼꼼해요.", "다음에도 여기서 살게요.",
        "품질 좋아요.", "만족합니다.", "잘 먹었어요 감사해요.", "예상 이상이에요.",
    ]
    user_names = [
        "김철수", "이영희", "박지훈", "최민수", "정수진", "강민지", "조현우", "윤서연", "장동혁", "한소희",
        "오세훈", "임지원", "송민호", "배수현", "홍길동", "김미영", "이준혁", "박서준", "최유나", "정다은",
        "강지민", "조은별", "윤도훈", "한지우", "오민지", "임현수", "송지아", "배준영", "홍수빈", "김동현",
        "맛집탐험가", "배송빠른곳", "신선한과일", "행복한식탁", "오늘저녁뭐먹지",
    ]
    products = Product.query.filter_by(is_active=True).all()
    cat_ids = {}
    created = 0
    for p in products:
        if p.category and p.category not in cat_ids:
            c = Category.query.filter_by(name=p.category).first()
            cat_ids[p.category] = c.id if c else None
        category_id = cat_ids.get(p.category)
        existing = Review.query.filter_by(product_id=p.id).count()
        to_add = max(0, count_per_product - existing)
        for j in range(to_add):
            virtual_order_id = -(p.id * 1000 + existing + j)
            if Review.query.filter_by(order_id=virtual_order_id).first():
                continue
            # 랜덤: 짧은 한줄 후기 vs 앞+중+뒤 조합
            if random.random() < 0.35:
                content = random.choice(review_one_liners)
            else:
                content = random.choice(review_starts) + random.choice(review_mids) + random.choice(review_ends)
            uname = random.choice(user_names)
            # 실제처럼 일부는 사진 없음 (약 30%)
            img = "" if random.random() < 0.3 else f"https://placehold.co/400x400/e0f2fe/1e40af?text=후기"
            r = Review(
                order_id=virtual_order_id,
                user_id=0,
                user_name=uname,
                product_id=p.id,
                product_name=p.name[:100] if p.name else "",
                category_id=category_id,
                content=content,
                image_url=img,
            )
            db.session.add(r)
            created += 1
    if created:
        db.session.commit()
    return created


@login_required
def admin_seed_test_data():
    """테스트 카테고리 3개 + 가상 상품 10개씩 생성 (관리자 전용)."""
    if not current_user.is_admin:
        return redirect('/')
    created = _seed_test_categories_and_products()
    flash(f"테스트 데이터 생성 완료. 새로 등록된 상품 {created}건 (카테고리·기존 상품은 중복 생성 안 함).")
    return redirect('/admin')


def _delete_test_categories_and_products():
    """테스트 카테고리(테스트-채소/과일/수산)와 해당 상품 전부 삭제. 삭제된 상품 수 반환."""
    test_cat_names = ["테스트-채소", "테스트-과일", "테스트-수산"]
    deleted_products = Product.query.filter(Product.category.in_(test_cat_names)).all()
    deleted_count = len(deleted_products)
    pids = [p.id for p in deleted_products]
    if pids:
        Review.query.filter(Review.product_id.in_(pids)).delete(synchronize_session=False)
    for p in deleted_products:
        db.session.delete(p)
    for name in test_cat_names:
        cat = Category.query.filter_by(name=name).first()
        if cat:
            db.session.delete(cat)
    db.session.commit()
    return deleted_count


@login_required
def admin_delete_test_data():
    """테스트 카테고리 및 해당 상품 전부 삭제 (관리자 전용)."""
    if not current_user.is_admin:
        return redirect('/')
    deleted = _delete_test_categories_and_products()
    flash(f"테스트 데이터 삭제 완료. 상품 {deleted}건 및 테스트 카테고리가 삭제되었습니다.")
    return redirect('/admin')


@login_required
def admin_orders_delete_all():
    """주문정보 전체 삭제 (Order, OrderItem 및 연관 테이블). 관리자 전용. POST + confirm=1."""
    if not current_user.is_admin:
        return redirect('/')
    if request.method != 'POST' or request.form.get('confirm') != '1':
        flash("주문 전체 삭제는 POST로 confirm=1 필요합니다.")
        return redirect('/admin?tab=orders')
    try:
        order_ids = [r.id for r in Order.query.with_entities(Order.id).all()]
        order_id_strs = [r.order_id or '' for r in Order.query.with_entities(Order.order_id).all() if r.order_id]
        if not order_ids:
            flash("삭제할 주문이 없습니다.")
            return redirect('/admin?tab=orders')
        # FK 순서: order_item 참조하는 것 먼저
        oi_ids = [r.id for r in OrderItem.query.filter(OrderItem.order_id.in_(order_ids)).with_entities(OrderItem.id).all()]
        EmailOrderLineStatus.query.filter(EmailOrderLineStatus.order_item_id.in_(oi_ids)).delete(synchronize_session=False) if oi_ids else None
        OrderItemLog.query.filter(OrderItemLog.order_id.in_(order_ids)).delete(synchronize_session=False)
        Settlement.query.filter(Settlement.order_id.in_(order_ids)).delete(synchronize_session=False)
        MarketingCost.query.filter(MarketingCost.order_id.in_(order_ids)).delete(synchronize_session=False)
        Review.query.filter(Review.order_id.in_(order_ids)).delete(synchronize_session=False)
        DeliveryTask.query.filter(DeliveryTask.order_id.in_(order_id_strs)).delete(synchronize_session=False)
        DeliveryLog.query.filter(DeliveryLog.order_id.in_(order_id_strs)).delete(synchronize_session=False)
        OrderItem.query.filter(OrderItem.order_id.in_(order_ids)).delete(synchronize_session=False)
        Order.query.filter(Order.id.in_(order_ids)).delete(synchronize_session=False)
        SellerOrderConfirmation.query.delete()
        db.session.commit()
        flash("주문정보 전체가 삭제되었습니다.")
    except Exception as e:
        db.session.rollback()
        flash(f"주문 전체 삭제 중 오류: {e}")
    return redirect('/admin?tab=orders')


@login_required
def admin_db_reset_all():
    """DB 전체 초기화 (주문·상품·카테고리·회원·게시판 등 모든 데이터 삭제). 마스터 관리자만. POST + 비밀번호 1234."""
    if not getattr(current_user, 'is_admin', False):
        return redirect('/')
    is_master = getattr(current_user, 'email', None) in (os.getenv('MASTER_ADMIN_EMAIL'),) or (current_user.is_admin and User.query.filter_by(is_admin=True).count() <= 1)
    if not is_master:
        flash("DB 전체 초기화는 마스터 관리자만 가능합니다.")
        return redirect('/admin')
    if request.method != 'POST':
        return redirect('/admin')
    if (request.form.get('db_reset_password') or '').strip() != '1234':
        flash('DB 전체 삭제를 하려면 비밀번호 1234 를 입력하세요.')
        return redirect('/admin?tab=products')
    try:
        # 1) 주문 연관
        order_ids = [r.id for r in Order.query.with_entities(Order.id).all()]
        order_id_strs = [r.order_id or '' for r in Order.query.with_entities(Order.order_id).all() if r.order_id]
        oi_ids = [r.id for r in OrderItem.query.filter(OrderItem.order_id.in_(order_ids)).with_entities(OrderItem.id).all()] if order_ids else []
        if oi_ids:
            EmailOrderLineStatus.query.filter(EmailOrderLineStatus.order_item_id.in_(oi_ids)).delete(synchronize_session=False)
        if order_ids:
            OrderItemLog.query.filter(OrderItemLog.order_id.in_(order_ids)).delete(synchronize_session=False)
            Settlement.query.filter(Settlement.order_id.in_(order_ids)).delete(synchronize_session=False)
            MarketingCost.query.filter(MarketingCost.order_id.in_(order_ids)).delete(synchronize_session=False)
            Review.query.filter(Review.order_id.in_(order_ids)).delete(synchronize_session=False)
        DeliveryTask.query.delete()
        DeliveryLog.query.delete()
        OrderItem.query.delete()
        Order.query.delete()
        SellerOrderConfirmation.query.delete()
        # 2) 상품·카테고리 연관
        ReviewVote.query.delete()
        Review.query.delete()
        Product.query.delete()
        CategorySettlement.query.delete()
        Category.query.delete()
        # 3) 회원 연관
        PointLog.query.delete()
        Cart.query.delete()
        UserMessage.query.delete()
        PushSubscription.query.delete()
        UserConsent.query.delete()
        # 4) 게시판
        BoardComment.query.delete()
        RestaurantRecommend.query.delete()
        RestaurantVote.query.delete()
        RestaurantRequest.query.delete()
        DeliveryRequestVote.query.delete()
        DeliveryRequest.query.delete()
        PartnershipInquiry.query.delete()
        FreeBoard.query.delete()
        EventPointRequest.query.delete()
        EventBoardPost.query.delete()
        ShareLink.query.delete()
        # 5) 기타
        DailyStat.query.delete()
        OrderViewLink.query.delete()
        MarketingAlimtalkLog.query.delete()
        db.session.commit()
        flash("DB 전체 초기화가 완료되었습니다. 카테고리·관리자 계정은 다시 등록해야 합니다.")
    except Exception as e:
        db.session.rollback()
        flash(f"DB 초기화 중 오류: {e}")
    return redirect('/admin')


